INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ПРОЕКТНАЯ ДЕЯТЕЛЬНОСТЬ КАК СРЕДСТВО РЕАЛИЗАЦИИ ФГОС ДО', 'proektnaya-deyatelnost-kak-sredstvo-realizatsii-fgos-do', 'Курс для педагогов ДОО, которые хотят освоить метод проектов как современный инструмент реализации ФГОС и научиться применять его в работе с детьми дошкольного возраста.', 'Воспитатель\nИзучите принципы и этапы организации проектной деятельности с дошкольниками, научитесь создавать условия для увлекательных и развивающих образовательных проектов.\nСтарший воспитатель (методист) \nРазберитесь в методах сопровождения проектной деятельности и получите инструменты для поддержки воспитателей в реализации проектов, соответствующих ФГОС ДО.', 'Дошкольное образование', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 6750, '[{"number": 1, "title": "Образовательные тренды в системе дошкольного образования"}, {"number": 2, "title": "Современные роли педагога. Компетенции педагога, необходимые для проектной деятельности"}, {"number": 3, "title": "Требования ФГОС ДО к организации проектной деятельности"}, {"number": 4, "title": "Метод проектов и его применение в современном дошкольном образовании"}, {"number": 5, "title": "Типы проектов. Основные этапы метода проектов"}, {"number": 6, "title": "Классификация педагогических технологий, используемых в проектной деятельности"}, {"number": 7, "title": "Проектная деятельность в работе с детьми младшего дошкольного возраста"}, {"number": 8, "title": "Проектная деятельность в работе с детьми старшего дошкольного возраста"}, {"number": 9, "title": "Организация развивающей предметно-пространственной среды в ДОО для проектной деятельности"}, {"number": 10, "title": "Вовлечение родителей на каждом этапе проектной деятельности"}]', '{"knowledge": ["требований ФГОС ДО к организации проектной деятельности", "сущности метода проектов и его применение в современном дошкольном образовании", "системы классификации проектов", "типов проектов в ДОО", "особенностей работы с детьми в условиях создания проекта"], "skills": ["разрабатывать проекты", "организовывать проектную деятельность в ДОО", "вовлекать родителей в проектную деятельность"], "abilities": ["разрабатывать проекты", "организовывать проектную деятельность в ДОО", "вовлекать родителей в проектную деятельность"]}', NULL, 1, 0);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('СОВРЕМЕННЫЕ ПОДХОДЫ К СОДЕРЖАНИЮ И ОРГАНИЗАЦИИ ОБРАЗОВАТЕЛЬНОГО ПРОЦЕССА В УСЛОВИЯХ РЕАЛИЗАЦИИ ФГОС ДО', 'sovremennye-podhody-k-soderzhaniyu-i-organizatsii-obrazovatelnogo-protsessa-v-usloviyah-realizatsii-fgos-do', 'Курс для педагогов, которые хотят качественно выстраивать воспитательно-образовательную деятельность в своей работе с дошкольниками.', 'Воспитатель\nНаучитесь организовывать образовательную деятельность согласно ФГОС ДО, планировать работу в соответствии с ФОП ДО, создавать развивающую РППС для полноценного развития детей.\nСтарший воспитатель (методист)\nОвладеете методами методического сопровождения педагогов, разберитесь в нормативно-правовой базе ФГОС ДО и ФОП ДО, будете обеспечивать контроль качества реализации программ.\nЗаведующий (директор)\nОбновите знания об организационно-хозяйственных, кадровых и материально-технических условиях ДОО, научитесь управлять образовательным процессом в соответствии с современными стандартами.', 'Дошкольное образование', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 6750, '[{"number": 1, "title": "Федеральный государственный образовательный стандарт дошкольного образования"}, {"number": 2, "title": "Образовательная деятельность в дошкольной образовательной организации"}, {"number": 3, "title": "Планирование образовательной деятельности в условиях реализации ФОП ДО"}, {"number": 4, "title": "Планируемые результаты дошкольного образования в условиях реализации ФОП ДО"}, {"number": 5, "title": "Организация развивающей предметно-пространственной среды и психологопедагогические условия"}, {"number": 6, "title": "Кадровые, финансовые условия и материально-техническое обеспечение"}]', '{"knowledge": ["основных способов и подходов к организации образовательного процесса в ДОО", "требований к структуре образовательной программы дошкольного образования и к ее объему", "структуры обновленной ФОП ДО"], "skills": ["организовывать виды деятельности, осуществляемые в раннем и дошкольном возрасте: предметная, познавательно-исследовательская, игра (ролевая, режиссерская, с правилом), продуктивная, конструирование, создания широких возможностей для развития свободной игры детей, в том числе обеспечения игрового времени и пространства", "проектировать отдельные разделы основной образовательной программы дошкольного образования", "адаптировать программы детского сада в соответствие с ФОП ДО"], "abilities": ["владеть навыками для планирования своей деятельности и организации образовательной деятельности в соответствии с ФГОС ДО и ФОП"]}', NULL, 1, 1);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ВОСПИТАТЕЛЬНАЯ РАБОТА В СОВРЕМЕННОЙ ДОО В УСЛОВИЯХ РЕАЛИЗАЦИИ ФГОС ДО', 'vospitatelnaya-rabota-v-sovremennoy-doo-v-usloviyah-realizatsii-fgos-do', 'Курс для тех, кто желает качественно выстроить воспитательный процесс с детьми в своей работе', 'Воспитатель\nНаучитесь выстраивать воспитательно-образовательную деятельность в соответствии с ФГОС ДО, организовывать эффективную работу по всем направлениям воспитания (социальное, патриотическое, экологическое), создавать условия для полноценного развития и социализации дошкольников.\nСтарший воспитатель (методист)\nОвладеете навыками методического руководства и сопровождения педагогов в организации воспитательной работы, разберитесь в требованиях ФГОС ДО и актуальных подходах к воспитанию, будете организовывать контроль качества реализации воспитательных программ в ДОО.\nПедагогический коллектив ДОО\nОбновите знания о целевых ориентирах воспитательной работы в дошкольной образовательной организации, научитесь формировать систему ценностей у детей, разработаете стратегию комплексной воспитательной деятельности в соответствии с современными стандартами.', 'Дошкольное образование', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 6750, '[{"number": 1, "title": "ФГОС ДО и задачи воспитательной работы современного детского сада"}, {"number": 2, "title": "Организация воспитательной работы в современной ДО"}, {"number": 3, "title": "Целевые ориентиры воспитательной работы в дошкольной образовательной организации. Система ценностей, её роль в формировании и становлении личности в дошкольном возрасте"}]', '{"knowledge": ["теоретических основ воспитательной работы в соответствии с ФГОС ДО и современными подходами к развитию детей дошкольного возраста", "целевых ориентиров и направлений воспитательной работы в дошкольной образовательной организации", "системы ценностей и их роли в формировании и становлении личности ребенка в дошкольном возрасте"], "skills": ["организовывать воспитательный процесс в соответствии с требованиями ФГОС ДО и современными подходами к воспитанию", "планировать и реализовывать воспитательные мероприятия по разным направлениям воспитания (социальное, патриотическое, экологическое и т.д.)", "создавать условия для формирования у дошкольников системы ценностей и нравственных основ"], "abilities": ["владеть методами и технологиями реализации воспитательной педагогической деятельности в процессе взаимодействия с детьми", "применять знания о возрастных психологических особенностях детей дошкольного возраста при организации воспитательной работы", "решать воспитательные задачи в процессе образовательной деятельности, игры и режимных моментов"]}', NULL, 1, 2);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ПАТРИОТИЧЕСКОЕ ВОСПИТАНИЕ ДЕТЕЙ ДОШКОЛЬНОГО ВОЗРАСТА В РАБОТЕ ПЕДАГОГА ДОО', 'patrioticheskoe-vospitanie-detey-doshkolnogo-vozrasta-v-rabote-pedagoga-doo', 'Курс для воспитателей, желающий экологично объяснить детям основы патриотического воспитания.', 'Воспитатель\nИзучите теории и практики патриотического воспитания, направленными на формирование у дошкольников гражданской ответственности и нравственных ориентиров.\nМетодист\nУзнаете, как организовать патриотическое воспитание в ДОУ: от планирования совместной деятельности с детьми до сопровождения педагогов в реализации воспитательных задач.', 'Дошкольное образование', 36, 'kpk', 'заочная с применением дистанционных образовательных технологий', 4800, '[{"number": 1, "title": "Значимость патриотического воспитания в ДОО"}, {"number": 2, "title": "Патриотическое и гражданское воспитание в ДОО в соответствии с ФГОС"}, {"number": 3, "title": "Педагогический инструментарий патриотического воспитания в ДОО"}, {"number": 4, "title": "Примеры парциальных программ и проектов"}]', '{"knowledge": ["актуальных проблем патриотического воспитания", "современных теорий и подходов к формированию навыков патриотического воспитания"], "skills": ["разрабатывать интерактивные задания для формирования патриотического воспитания", "заинтересовать родителей и вовлечь их в создание единого культурно-образовательного пространства «детский сад-семья»", "организовывать предметно-развивающую среду в группе"], "abilities": ["актуальных проблем патриотического воспитания", "современных теорий и подходов к формированию навыков патриотического воспитания"]}', NULL, 1, 3);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ОРГАНИЗАЦИЯ ВЗАИМОДЕЙСТВИЯ С РОДИТЕЛЯМИ ДЕТЕЙ ДОШКОЛЬНОГО ВОЗРАСТА В СООТВЕТСТВИИ С ФОП ДО', 'organizatsiya-vzaimodeystviya-s-roditelyami-detey-doshkolnogo-vozrasta-v-sootvetstvii-s-fop-do', 'Курс для воспитателей, желающих найти подход к родителям дошкольников и организовывать взаимодействие с семьей в соответствии с ФОП ДО.', 'Воспитатель\nНаучитесь находить подход к родителям дошкольников, организовывать эффективное взаимодействие с семьей в соответствии с ФОП ДО, применять современные формы и технологии сотрудничества, разрешать конфликтные ситуации конструктивным путем.\nСтарший воспитатель (методист)\nОвладеете методами методического сопровождения педагогов в организации работы с родителями, разберитесь в нормативно-правовой базе взаимодействия детского сада с семьями воспитанников, будете координировать различные направления сотрудничества ДОО с семьей согласно ФОП ДО.\nЗаведующий ДОО\nОбновите знания о нормативно-правовых условиях и требованиях к взаимодействию образовательного учреждения с семьями воспитанников, научитесь создавать условия для участия родителей в образовательной деятельности, разработаете стратегию партнерского сотрудничества ДОО с семьей.', 'Дошкольное образование', 36, 'kpk', 'заочная с применением дистанционных образовательных технологий', 4800, '[{"number": 1, "title": "Нормативно-правовая база взаимодействия детского сада с семьями воспитанников с учетом реализации ФОП ДО"}, {"number": 2, "title": "Создание условий для участия родителей в образовательной деятельности"}, {"number": 3, "title": "Взаимодействие педагога с семьями дошкольников в соответствии с ФОП ДО"}, {"number": 4, "title": "Эффективное разрешение конфликтов в ДО"}]', '{"knowledge": ["актуальности взаимодействия с родителями (законными представителями)", "целей, задач и принципов взаимодействия с родителями (законными представителями) с учетом реализации ФОП ДО", "направлений, форм и технологий взаимодействия с семьей в соответствии с ФОП ДО"], "skills": ["применять формы и технологии взаимодействия с семьей в соответствии с ФОП ДО", "выявлять потребностей и интересов семьи", "организовывать поддержку образовательных инициатив семьи", "эффективно разрешать конфликты в ДО"], "abilities": ["применять различные методы и формы для организации взаимодействия с родителями детей дошкольного возраста в соответствии с ФОП ДО"]}', NULL, 1, 4);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('РЕАЛИЗАЦИЯ ПАРЦИАЛЬНОЙ МОДУЛЬНОЙ ПРОГРАММЫ «STEM-ОБРАЗОВАНИЕ ДЕТЕЙ ДОШКОЛЬНОГО ВОЗРАСТА»', 'realizatsiya-partsialnoy-modulnoy-programmy-stem-obrazovanie-detey-doshkolnogo-vozrasta', 'Курс для тех, кто стремится освоить STEAM-подход и использовать его для развития у дошкольников основ инженерно-технического мышления.', 'Воспитатель\nОвладейте современными методиками организации проведения занятий в рамках STEАM-образования для дошкольников.\nМетодист\nОбеспечьте методическое сопровождение педагогов и координацию внедрения STEAM-подхода в дошкольных учреждениях.', 'Дошкольное образование', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 7200, '[{"number": 1, "title": "Основы STEAM-образования в дошкольной организации"}, {"number": 2, "title": "Организация предметно-пространственной среды в рамках STEAM-подхода"}, {"number": 3, "title": "Исследовательская и экспериментальная деятельность дошкольников"}, {"number": 4, "title": "Конструирование, инженерное мышление и робототехника в STEAM"}, {"number": 5, "title": "Математическое грамотность в STEAM"}, {"number": 6, "title": "Art-компонент в STEAM-подходе"}, {"number": 7, "title": "Проектная деятельность в STEAM-образовании"}, {"number": 8, "title": "Цифровые компетенции современного педагога"}]', '{"knowledge": ["теоретических основ STEAM-подхода и принципов его интеграции в образовательный процесс", "содержания STEAM-подхода и требований к организации предметно-пространственной среды", "особенностей организации проектной деятельности в рамках STEAM-направления"], "skills": ["применять STEAM-подход при планировании и организации образовательной деятельности", "создавать предметно-пространственную среду, поддерживающую исследовательскую, экспериментальную, конструктивную и творческую активность детей", "организовывать проектную деятельность дошкольников в рамках STEAM-подхода"], "abilities": ["реализации STEAM-подхода в дошкольной образовательной организации"]}', NULL, 1, 5);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('СЕМЕЙНО-НРАВСТВЕННОЕ РАЗВИТИЕ И ГЕНДЕРНОЕ (ПОЛОВОЕ) ВОСПИТАНИЕ ДЕТЕЙ ДОШКОЛЬНОГО И ШКОЛЬНОГО ВОЗРАСТОВ', 'semeyno-nravstvennoe-razvitie-i-gendernoe-polovoe-vospitanie-detey-doshkolnogo-i-shkolnogo-vozrastov', 'Курс для тех, кто хочет получить ответы на все наболевшие вопросы по половому воспитанию и семейно-нравственному развитию “простыми словами о сложном” и сформировать навыки безопасного поведения детей', 'Воспитатель\nНаучитесь организовывать работу по семейно-нравственному и половому воспитанию детей в соответствии с возрастными особенностями, формировать навыки безопасного поведения, проводить просветительскую работу с родителями по вопросам полового воспитания в доступной и корректной форме.', 'Дошкольное образование', 16, 'kpk', 'заочная с применением дистанционных образовательных технологий', 2325, '[{"number": 1, "title": "Теоретико-методологические основы семейно-нравственного и полового воспитания"}, {"number": 2, "title": "Половое воспитание по возрастам"}, {"number": 3, "title": "Родительская программа полового воспитания и развития детей и подростков"}, {"number": 4, "title": "Половое воспитание: как обезопасить ребенка и оказать своевременную помощь"}, {"number": 5, "title": "Возможности взаимодействия образовательных организаций с различными организациями по вопросу профилактики сексуального насилия"}]', '{"knowledge": ["роли социального педагога и психолога в семейно-нравственном и половом воспитании детей", "основ формирования здоровых нравственных отношений в социальной среде", "психологических особенности детей и подростков в вопросах психосексуального развития", "признаков сексуального насилия и эксплуатации у детей и знаний в области оказания психологической помощи детям, пострадавшим от сексуального насилия и эксплуатации"], "skills": ["выстраивать план воспитательной работы по направлению семейного воспитания детей", "рассказывать ребёнку о теле, границах, гигиене, половых отношениях и безопасности без вреда для психики", "грамотно и спокойно ответите на «неудобные» вопросы", "формировать навыки безопасного поведения детей в образовательной организации и за ее пределами"]}', NULL, 1, 6);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ИННОВАЦИОННЫЕ МЕТОДИКИ ТРИЗ В ДОШКОЛЬНОМ ОБРАЗОВАНИИ: ОРГАНИЗАЦИЯ И ПРОВЕДЕНИЕ ЗАНЯТИЙ', 'innovatsionnye-metodiki-triz-v-doshkolnom-obrazovanii-organizatsiya-i-provedenie-zanyatiy', 'Курс для творческих педагогов, кто желает применять ТРИЗ технологию на занятиях с дошкольниками', 'Воспитатель \nНаучитесь применять инновационные методики ТРИЗ в организации и проведении занятий с дошкольниками, развивать у детей творческие способности и навыки решения изобретательских задач, использовать технологию ТРИЗ для реализации принципов ФГОС ДО в работе с детьми разных возрастных групп.\nСтарший воспитатель \nОвладеете концептуальными и методическими основами ТРИЗ, разберитесь в возможностях использования технологии для развития детей дошкольного возраста, будете оказывать методическое сопровождение педагогам по внедрению ТРИЗ в образовательный процесс ДОО.\nПедагог дополнительного образования\nОбновите знания о способах развития у детей навыков и компетенций XXI века через применение ТРИЗ, научитесь организовывать творческую деятельность с использованием технологии решения изобретательских задач, сможете применять ТРИЗ при работе с детьми разных возрастов.', 'Дошкольное образование', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 6750, '[{"number": 1, "title": "Концептуальные и методические основы ТРИЗ"}, {"number": 2, "title": "Возможность использования технологии решения изобретательских задач для реализации принципов ФГОС дошкольного образования"}, {"number": 3, "title": "Использование ТРИЗ в развитии детей дошкольного возраста"}, {"number": 4, "title": "Особенности использования ТРИЗ при работе с детьми разных возрастных групп"}, {"number": 5, "title": "Возможности ТРИЗ для развития у детей навыков и компетенций XXI века"}]', '{"knowledge": ["концептуальных основ данной теории, методов и этапов ее использования в дошкольном образовании", "методики разработки и решения изобретательских задач", "особенностей применения ТРИЗ в работе с детьми различных возрастных групп"], "skills": ["находить возможности использования данной технологии в развитии дошкольников", "внедрять элементы ТРИЗ в воспитательный процесс ДОО", "применять технологию на занятиях, способствующих речевому, познавательному, творческому развитию воспитанников"], "abilities": ["приемами включения теории решения изобретательских задач в работу с дошкольниками разного возраста"]}', NULL, 1, 7);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('КОРРЕКЦИОННАЯ РАБОТА С ДЕТЬМИ, ИМЕЮЩИМИ РАССТРОЙСТВО АУТИСТИЧЕСКОГО СПЕКТРА, В УСЛОВИЯХ ДОШКОЛЬНОГО ОБРАЗОВАНИЯ', 'korrektsionnaya-rabota-s-detmi-imeyuschimi-rasstroystvo-autisticheskogo-spektra-v-usloviyah-doshkolnogo-obrazovaniya', 'Курс для специалистов, которые хотят овладеть современными методиками коррекционной работы с детьми, имеющими расстройства аутистического спектра, и обеспечить им качественное сопровождение в условиях дошкольного образования.', 'Логопед-дефектолог\nОвладеете техниками диагностики, планирования и сопровождения коррекционной работы с детьми с РАС в условиях дошкольной инклюзии.', 'Дошкольное образование', 144, 'kpk', 'заочная с применением дистанционных образовательных технологий', 7800, '[{"number": 1, "title": "Особенности коррекционной помощи детям с РАС в рамках дошкольного учреждения"}, {"number": 2, "title": "Клинико-психологическая характеристика детского аутизма и расстройств аутистического спектра"}, {"number": 3, "title": "Диагностические мероприятия для определения вида и характера РАС у ребенка"}, {"number": 4, "title": "Оказание коррекционной помощи при расстройствах аутистического спектра"}, {"number": 5, "title": "Разработка и реализация АОП"}, {"number": 6, "title": "Разработка и реализация ИОМ"}]', '{"knowledge": ["особенностей коррекционной помощи детям с РАС в рамках дошкольного учреждения", "клинико-психологических характеристик детского аутизма и расстройств аутистического спектра", "способов выстраивания коррекционного маршрута для детей с РАС"], "skills": ["используя различные методики, комбинируя их, выстраивать индивидуальный коррекционный маршрут", "проводить диагностику детей с РАС", "выстраивать коррекционный маршрут, учитывая индивидуальные особенности и результаты диагностики"], "abilities": ["использовать различные методики проведения диагностики детей дошкольного возраста с РАС", "использовать результаты диагностики при планировании коррекционного маршрута", "сопровождения семей с детьми с РАС"]}', NULL, 1, 8);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ИСТОРИЧЕСКОЕ ПРОСВЕЩЕНИЕ ДЕТЕЙ ДОШКОЛЬНОГО ВОЗРАСТА В УСЛОВИЯХ ОБРАЗОВАТЕЛЬНОГО ПРОЦЕССА ДОУ', 'istoricheskoe-prosveschenie-detey-doshkolnogo-vozrasta-v-usloviyah-obrazovatelnogo-protsessa-dou', 'Курс для воспитателей и педагогов, которые хотят научиться организовывать различные формы исторического просвещения детей дошкольного возраста, формируя у них гражданскую идентичность и уважение к историческому наследию в условиях образовательного процесса', 'Воспитатель\nОсвойте современные подходы к историческому просвещению дошкольников, формируя у детей основы гражданской идентичности и уважение к историческому наследию.\nМетодист\nРазберетесь в подходах к организации исторического просвещения в ДОУ с учётом возраста детей, актуальных нормативных требований и воспитательных целей.', 'Дошкольное образование', 36, 'kpk', 'заочная с применением дистанционных образовательных технологий', 4800, '[{"number": 1, "title": "Нормативно-правовые основания исторического просвещения"}, {"number": 2, "title": "Содержание исторического просвещения в ДОУ"}, {"number": 3, "title": "Историческое просвещение в ДОУ: как организовать?"}, {"number": 4, "title": "Способы оценки результатов исторического просвещения детей дошкольного возраста"}]', '{"knowledge": ["нормативных оснований исторического просвещения в системе образования", "форм, методов и содержания исторического просвещения детей дошкольного возраста"], "skills": ["выбирать направления исторического просвещения детей дошкольного возраста", "организовывать различные формы исторического просвещения детей дошкольного возраста в условиях образовательного процесса ДОУ", "оценивать результаты исторического просвещения детей в ДОУ"], "abilities": ["владения методикой организации исторического просвещения детей в условиях образовательного процесса в ДОУ"]}', NULL, 1, 9);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ТРУДОВОЕ ВОСПИТАНИЕ ДЕТЕЙ ДОШКОЛЬНОГО ВОЗРАСТА В СООТВЕТСТВИИ С ФОП ДО', 'trudovoe-vospitanie-detey-doshkolnogo-vozrasta-v-sootvetstvii-s-fop-do', 'Курс полезен воспитателям, желающим обладать компетенциями для эффективной организации трудового воспитания детей, способствуя их гармоничному развитию и подготовке к жизни.', 'Воспитатель \nНаучитесь планировать и проводить занятия по трудовому воспитанию, развивая у детей навыки самостоятельности, творческого мышления, уважения к труду и подготавливая их к жизни в современном обществе.\nСтарший воспитатель (методист)\nОвладеете современными подходами к организации трудового воспитания в соответствии с ФОП ДО, различными формами и направлениями, а также методами работы с родителями в процессе трудового воспитания дошкольников.', 'Дошкольное образование', 16, 'kpk', 'заочная с применением дистанционных образовательных технологий', 3600, '[{"number": 1, "title": "Трудовое воспитание детей дошкольного возраста в соответствии с ФОП ДО"}, {"number": 2, "title": "Формы и направления трудового воспитания детей дошкольного возраста"}, {"number": 3, "title": "Организация труда детей дошкольного возраста"}, {"number": 4, "title": "Работа с родителями в процессе привлечения дошкольников к труду"}]', '{"knowledge": ["понятия «трудовое воспитание» согласно ФОП ДО", "форм и направлений трудового воспитания детей дошкольного возраста", "форм работы с родителями в процессе привлечения дошкольников к труду"], "skills": ["определять подходящую форму и направление трудового воспитания", "формировать и организовывать трудовое воспитание в своей группе", "выстраивать партнерские отношения с родителями по трудовому воспитанию"], "abilities": ["применения методов и форм для организации трудового воспитания дошкольников"]}', NULL, 1, 10);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('РАЗВИТИЕ ДЕТЕЙ ДОШКОЛЬНОГО ВОЗРАСТА НА ОСНОВЕ ТРАДИЦИОННЫХ ДУХОВНО-НРАВСТВЕННЫХ И СОЦИОКУЛЬТУРНЫХ ЦЕННОСТЕЙ РОССИЙСКОГО НАРОДА В СООТВЕТСТВИИ С ФОП ДО', 'razvitie-detey-doshkolnogo-vozrasta-na-osnove-traditsionnyh-duhovno-nravstvennyh-i-sotsiokulturnyh-tsennostey-rossiyskog', 'Курс для воспитателей, желающих организовывать деятельность с воспитанниками для повышения духовно-нравственного воспитания.', 'Воспитатель\nСовершенствуете организационные и методические подходы к развитию духовно-нравственной культуры детей и взаимодействию с семьями.\nМетодист\nРазработаете методические рекомендации и сопровождение педагогов по формированию духовно-нравственных и социокультурных ценностей у детей в рамках ФОП ДО.', 'Дошкольное образование', 36, 'kpk', 'заочная с применением дистанционных образовательных технологий', 4800, '[{"number": 1, "title": "Значение духовно-нравственного воспитания в образовательном процессе с учетом реализации ФОП ДО"}, {"number": 2, "title": "Организационно-методические основы формирования духовно-нравственной культуры у детей"}, {"number": 3, "title": "Духовно-нравственное воспитание детей в условиях образовательной организации"}, {"number": 4, "title": "Организация взаимодействия образовательной организации с семьей для повышения эффективности духовно-нравственного воспитания"}]', '{"knowledge": ["места и роли духовно-нравственного воспитания в ФГОС и ФОП ДО", "психологических оснований процесса духовно-нравственного воспитания личности в дошкольном возрасте", "особенностей организации работы в сфере духовно-нравственного воспитания детей"], "skills": ["применять различные методические подходы в зависимости от возрастных особенностей детей", "разрабатывать и проводить занятия, игры и другие мероприятия, направленные на развитие духовно-нравственных ценностей", "организовывать взаимодействие образовательной организации с семьей для повышения эффективности духовно-нравственного воспитания"], "abilities": ["применения методических подходов для развития у детей дошкольного возраста духовно-нравственных и социокультурных ценностей российского народа в соответствии с ФОП ДО"]}', NULL, 1, 11);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ФОРМИРОВАНИЕ ПЕРВОНАЧАЛЬНЫХ ИССЛЕДОВАТЕЛЬСКИХ НАВЫКОВ У ДЕТЕЙ СТАРШЕГО ДОШКОЛЬНОГО ВОЗРАСТА В СООТВЕТСТВИИ ФГОС', 'formirovanie-pervonachalnyh-issledovatelskih-navykov-u-detey-starshego-doshkolnogo-vozrasta-v-sootvetstvii-fgos', 'Курс для педагогов, желающих организовывать познавательно-исследовательскую деятельность детей старшего дошкольного возраста.', 'Воспитатель \nНаучитесь организовывать познавательно-исследовательскую деятельность детей, развивая у них первоначальные исследовательские навыки, базовые компетенции XXI века и готовность к успешному обучению в школе.\n​Старший воспитатель (методист)\nОвладеете закономерностями и этапами формирования исследовательской деятельности, методами создания индивидуальных образовательных маршрутов, а также способами взаимодействия с семьями в формировании исследовательских умений.', 'Дошкольное образование', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 6600, '[{"number": 1, "title": "Ключевые современные образовательные тренды в России и мире"}, {"number": 2, "title": "Базовые навыки XXI века"}, {"number": 3, "title": "Детская исследовательская деятельность как один из инструментов формирования успешности детей старшего дошкольного возраста"}, {"number": 4, "title": "Закономерности и этапы формирования и организации исследовательской деятельности детей старшего дошкольного возраста"}, {"number": 5, "title": "Роль и функции педагога и семьи в формировании первоначальных исследовательских навыков"}, {"number": 6, "title": "Создание индивидуального образовательного маршрута для семьи и детей старшего дошкольного возраста"}, {"number": 7, "title": "Развитие исследовательских умений и навыков у детей старшего дошкольного возраста"}]', '{"knowledge": ["целей и задач организации познавательно-исследовательской деятельности, особенностей современных подходов к инновационной деятельности, основанных на требованиях нормативных документов", "характеристик познавательно-исследовательской деятельности", "специфики системно-деятельностного подхода и педагогические технологии, обеспечивающие его реализацию в образовательном процессе"], "skills": ["организовывать познавательно-исследовательскую деятельность на основе требований ФГОС"], "abilities": ["владеть способами организации познавательно-исследовательской деятельности с детьми старшего дошкольного возраста"]}', NULL, 1, 12);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('РАННЯЯ ПРОФОРИЕНТАЦИЯ ДОШКОЛЬНИКОВ В УСЛОВИЯХ РЕАЛИЗАЦИИ ФГОС', 'rannyaya-proforientatsiya-doshkolnikov-v-usloviyah-realizatsii-fgos', 'Курс для педагогов, желающих формировать раннюю профессиональную ориентацию детей дошкольного возраста.', 'Воспитатель  \nОсвоете современные подходы к ранней профориентации дошкольников, научитесь планировать и организовывать профориентационную деятельность в детском саду, применяя эффективные технологии и методы для формирования у детей интереса к миру профессий.​\n\nСтарший воспитатель (методист) \nРазберетесь в стратегии организации профориентационной работы в ДОУ, изучите современные технологии и формы взаимодействия с социальными партнерами, научитесь оценивать результаты профориентационной деятельности и выстраивать эффективные программы в соответствии с ФГОС.​', 'Дошкольное образование', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 6675, '[{"number": 1, "title": "Планирование и организация профориентационной деятельности в дошкольных образовательных организациях"}, {"number": 2, "title": "Технологии, формы и методы профориентационной деятельности в дошкольных образовательных организациях"}, {"number": 3, "title": "Организация взаимодействия дошкольной образовательной организации с социальными партнерами и родителями"}, {"number": 4, "title": "Мониторинг качества профориентационной работы"}]', '{"knowledge": ["понятий «допрофессиональное самоопределение» и «ранняя профориентация» детей", "задач профориентационной работы с детьми дошкольного возраста"], "skills": ["планировать и организовывать профориентационную деятельность в дошкольных образовательных организациях", "создавать условия для формирования у детей представлений о труде взрослых в рамках образовательных программ дошкольного образования", "проводить мониторинг качества профориентационной работы", "планировать и организовывать взаимодействие дошкольной образовательной организации с социальными партнерами и родителями"], "abilities": ["технологиями, формами и методами профориентационной деятельности в дошкольных образовательных организациях", "формами и методами работы с детьми по формированию представлений о труде взрослых"]}', NULL, 1, 13);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('РАЗВИТИЕ ПРОФЕССИОНАЛЬНОЙ КОМПЕТЕНТНОСТИ ВОСПИТАТЕЛЯ ПО ФОРМИРОВАНИЮ ФУНКЦИОНАЛЬНОЙ ГРАМОТНОСТИ ДОШКОЛЬНИКОВ', 'razvitie-professionalnoy-kompetentnosti-vospitatelya-po-formirovaniyu-funktsionalnoy-gramotnosti-doshkolnikov', 'Курс для педагогов, кто желает формировать функциональную грамотность у детей, как средство раскрытия учебных навыков и возможностей.', 'Воспитатель\nИзучите, как формировать у дошкольников читательскую, финансовую и правовую грамотность с учётом возрастных особенностей и требований ФГОС ДО.\nМетодист\nРазберитесь в технологиях формирования функциональной грамотности в ДОУ и получите инструменты для методического сопровождения педагогов в развитии у детей ключевых навыков и умений.', 'Дошкольное образование', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 6825, '[{"number": 1, "title": "Функциональная грамотность детей дошкольного возраста"}, {"number": 2, "title": "Читательская грамотность дошкольников в соответствии с ФГОС ДОО: проблемы и решения"}, {"number": 3, "title": "Финансовая грамотность – понятие, роль, необходимость формирования финансовой грамотности у граждан"}, {"number": 4, "title": "Формирование правовой грамотности дошкольников"}]', '{"knowledge": ["нормативно-правовых основ формирования функциональной грамотности дошкольников в условиях реализации ФГОС ДО", "технологий формирования функциональной грамотности детей дошкольного возраста", "методов и приемов формирования читательской грамотности дошкольников", "целей формирования финансовой грамотности у дошкольников"], "skills": ["организовывать образовательную деятельность с учетом формирования функциональной грамотности дошкольников", "привлекать родителей воспитанников к сотрудничеству в формировании читательской, финансовой и правовой грамотности"], "abilities": ["владеть приемами и формами работы по формированию читательской грамотности у детей", "владеть принципами построения занятий для дошкольников по финансовой грамотности", "владеть методами и приемами формирования правовой грамотности дошкольников"]}', NULL, 1, 14);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ОРГАНИЗАЦИЯ ДЕЯТЕЛЬНОСТИ ДОШКОЛЬНОЙ ОБРАЗОВАТЕЛЬНОЙ ОРГАНИЗАЦИИ ПО ФОРМИРОВАНИЮ ЗДОРОВОГО ОБРАЗА ЖИЗНИ У ДЕТЕЙ ДОШКОЛЬНОГО ВОЗРАСТА', 'organizatsiya-deyatelnosti-doshkolnoy-obrazovatelnoy-organizatsii-po-formirovaniyu-zdorovogo-obraza-zhizni-u-detey-doshk', 'Курс для педагогов, желающих привить дошкольникам любовь к здоровому образу жизни.', 'Воспитатель\nПриобретете современные знания и практические навыки по формированию здорового образа жизни у дошкольников, освоете эффективные здоровьесберегающие технологии в соответствии с требованиями ФГОС ДО, научитесь развивать у детей первоначальные навыки социального взаимодействия как одного из факторов их психологического здоровья.​\n\nСтарший воспитатель (методист)\nРазберетесь в нормативно-правовых основаниях деятельности ДОО по формированию здорового образа жизни, овладеете методологией применения современных здоровьесберегающих технологий, научитесь организовать работу педагогического коллектива по развитию навыков социального взаимодействия у дошкольников в соответствии с актуальными требованиями.​', 'Дошкольное образование', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 6225, '[{"number": 1, "title": "Нормативно - правовое обеспечение деятельности педагогических работников и специалистов ДОО по формирования здорового образа жизни в Российской Федерации"}, {"number": 2, "title": "Применение здоровьесберегающих технологий в соответствии с требованиями ФГОС ДО"}, {"number": 3, "title": "Формирование навыков социального взаимодействия у дошкольников, как один из факторов психологического здоровья ребенка"}]', '{"knowledge": ["принципов ведения здорового образа жизни", "основ здоровьесберегающих технологий в педагогической деятельности", "особенностей формирования привычек к ЗОЖ у детей дошкольного возраста", "методов и технологии проведения мероприятий по сохранению и укреплению здоровья в дошкольной образовательной организации"], "skills": ["прогнозировать результаты педагогической деятельности в направлении формирования привычек к ЗОЖ у воспитанников ДОО", "организовать воспитательную работу в направлении сохранения и укрепления здоровья воспитанников"], "abilities": ["владеть инструментами формирования у детей дошкольного возраста положительного отношения к экологии, собственному здоровью, ведению здорового образа жизни", "владеть методами педагогической работы, способствующими гармоничному умственному и физическому развитию детей"]}', NULL, 1, 15);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ИГРОВОЕ ПРОСТРАНСТВО: СОЗДАНИЕ РАЗВИВАЮЩЕЙ СРЕДЫ В ДОО В СООТВЕТСТВИИ ФГОС ДО', 'igrovoe-prostranstvo-sozdanie-razvivayuschey-sredy-v-doo-v-sootvetstvii-fgos-do', 'Курс для педагогов, желающих методически грамотно включать разные виды игр в качестве средств организации познавательной, творческой активности и развития детей.', 'Воспитатель \nМетодически грамотно спроектируете и организуете игровую деятельность как основное средство обучения и развития дошкольников. Освоите создание и использование развивающей предметно-пространственной среды в соответствии с ФГОС ДО и ФОП ДО. Овладеете практическими навыками включения разных видов игр в качестве средств организации познавательной и творческой активности детей.​\nСтарший воспитатель\nРазберетесь в нормативных требованиях к игровой деятельности согласно ФГОС и ФОП ДО. Овладеете подходами к организации современной игровой деятельности в ДОО. Научитесь координировать работу педагогического коллектива по проектированию развивающей предметно-пространственной среды и воспитательной работы с учётом актуальных стандартов.​', 'Дошкольное образование', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 7650, '[{"number": 1, "title": "ФГОС и ФОП ДО: нормативные требования к игровой деятельности"}, {"number": 2, "title": "Образовательная деятельность в дошкольной образовательной организации"}, {"number": 3, "title": "ФГОС и ФОП ДО: задачи воспитательной работы современного детского сада"}, {"number": 4, "title": "Современная организация игровой деятельности в детском саду в условиях реализации ФГОС"}, {"number": 5, "title": "Игра в образовательном процессе ДОО"}, {"number": 6, "title": "Организация развивающей предметно - пространственной среды"}, {"number": 7, "title": "Взаимодействие педагога с родителями дошкольников"}]', '{"knowledge": ["нормативно-правовой основы реализации ФГОС дошкольного образования", "целевых ориентиров и планируемых результатов освоения образовательных программ дошкольного образования", "особенностей сущности, структуры и содержания воспитательного процесса", "классификации и структуры игр, значения игровой деятельности в дошкольном образовании"], "skills": ["осуществлять выбор и проектирование образовательных и игровых технологий при работе с детьми", "организовать взаимодействие взрослых с детьми", "организовать взаимодействие педагогического коллектива с семьями дошкольников", "планировать образовательный процесс в дошкольной образовательной организации"], "abilities": ["владеть основами проектирования педагогического процесса, а также основами применения", "современных образовательных (воспитательных и обучающих) технологий при работе с детьми"]}', NULL, 1, 16);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('СОВРЕМЕННЫЕ ПОДХОДЫ К ОБУЧЕНИЮ ГРАМОТЕ ДОШКОЛЬНИКОВ В СООТВЕТСТВИИ С ТРЕБОВАНИЯМИ ФОП ДО', 'sovremennye-podhody-k-obucheniyu-gramote-doshkolnikov-v-sootvetstvii-s-trebovaniyami-fop-do', 'Курс для педагогов, желающих использовать разные приемы и методики в проведении занятий по обучению грамоте.', 'Воспитатель\nИзучите современные методики обучения грамоте дошкольников и научитесь создавать мотивационную и эффективную образовательную среду, учитывая требования ФОП ДО.\nМетодист\nПознакомьтесь с инновационными подходами к обучению грамоте в ДОУ и получите навыки сопровождения педагогов в применении современных методик и анализе образовательного процесса.', 'Дошкольное образование', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 6750, '[{"number": 1, "title": "Обучение грамоте в детском саду: особенности и приёмы"}, {"number": 2, "title": "Методики обучения грамоте дошкольников. Использование игр и пособий"}, {"number": 3, "title": "Особенности онлайн-занятий с дошкольниками"}, {"number": 4, "title": "Анализ занятия"}]', '{"knowledge": ["целей и задач обучения грамоте дошкольников", "форм и методов обучения", "современных методик обучения грамоте", "дидактических игр и упражнений по обучению грамоте"], "skills": ["работать на онлайн-платформах", "мотивировать ребенка к занятию", "проводить анализ занятия"], "abilities": ["владеть методами обучения дошкольников грамоте"]}', NULL, 1, 17);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('РАЗВИТИЕ РЕБЕНКА В РАННЕМ ВОЗРАСТЕ (ОТ 0 ДО 3-Х ЛЕТ) В СООТВЕТСТВИИ С ФГОС ДО', 'razvitie-rebenka-v-rannem-vozraste-ot-0-do-3-h-let-v-sootvetstvii-s-fgos-do', 'Курс для тех, кому необходимо повышение профессиональной и методической компетенции педагога в развитии ребенка в раннем возрасте (от 0 до 3-х лет).', 'Воспитатель \nПовысите профессиональную и методическую компетенцию в понимании психофизиологического развития детей раннего возраста. Освоите практические технологии проведения развивающих игр-занятий с детьми от 0 до 3-х лет. Овладеете навыками создания условий для полноценного развития малышей в соответствии с ФГОС ДО.​\nСтарший воспитатель (методист) \nРазберетесь в современных подходах к развитию детей раннего возраста и анализу существующих образовательных программ. Овладеете методологией организации развивающей предметно-пространственной среды для детей от 0 до 3-х лет. Научитесь координировать работу педагогического коллектива по взаимодействию с семьями воспитанников раннего возраста.​\nЗаведующий (директор)\nОбновите знания о нормативных требованиях к развитию детей раннего возраста согласно ФГОС ДО. Овладеете стратегиями создания условий для психофизиологического развития детей от 0 до 3-х лет. Выстроите эффективную политику организации, ориентированную на организацию взаимодействия с семьями и комплексное развитие малышей.', 'Дошкольное образование', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 6675, '[{"number": 1, "title": "Психофизиологическое развитие детей от 0 до 3-х лет"}, {"number": 2, "title": "Создание условий для развития детей от 0 до 3-х лет"}, {"number": 3, "title": "Анализ существующих образовательных программ для детей раннего возраста"}, {"number": 4, "title": "Технология проведения развивающих игр-занятий с детьми раннего возраста"}, {"number": 5, "title": "Особенности организации взаимодействия с семьями"}]', '{"knowledge": ["возрастных физиологических и психологических новообразований раннего детства", "основ развития психических функций (речь, восприятие, мышление, внимание, память) в раннем детстве", "основ становление личности ребенка, его системы «Я»", "основных методов и порядка проведения диагностики детей периода раннего детства"], "skills": ["разрабатывать и проводить диагностику детей раннего возраста", "проектировать, организовывать и реализовывать игры-занятия для детей раннего возраста"], "abilities": ["владеть современными методиками развития детей раннего возраста", "владеть навыками построения игр-занятий для детей раннего возраста"]}', NULL, 1, 18);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('НЕЙРОПЕДАГОГИЧЕСКИЕ ТЕХНИКИ И МЕТОДИКИ В ДОШКОЛЬНОМ ОБРАЗОВАНИИ', 'neyropedagogicheskie-tehniki-i-metodiki-v-doshkolnom-obrazovanii', 'Курс полезен педагогам, работающим с детьми дошкольного возраста и желающим использовать приемы и техники нейропедагогики в работе', 'Воспитатель\nОвладеете методическими и психолого-педагогическими подходами к развитию детей раннего возраста, освоите технологии проведения развивающих игр-занятий, выстроите эффективное взаимодействие с семьями детей от 0 до 3 лет.\nСтарший воспитатель (методист)\nРазберетесь в психофизиологических особенностях развития детей раннего возраста, научитесь анализировать и выбирать образовательные программы для малышей, получите инструменты для методического сопровождения педагогов в работе с детьми от 0 до 3 лет.\nПедагог-психолог \nУглубите знания о психолого-педагогических закономерностях раннего развития, освоите методики диагностики и сопровождения развития детей от 0 до 3 лет, выстроите эффективное взаимодействие с семьями для оптимизации условий развития малышей.', 'Дошкольное образование', 36, 'kpk', 'заочная с применением дистанционных образовательных технологий', 4800, '[{"number": 1, "title": "Развитие мозга ребенка через нейропедагогические методики"}, {"number": 2, "title": "Применение нейропедагогических методик и приемов в образовательной деятельности ДОО"}]', '{"knowledge": ["основ нейропедагогики и ее принципов", "особенностей развития мозга ребенка и влияние нейропедагогических методик на развитие детей", "методов и техник нейропедагогики для развития различных навыков у детей"], "skills": ["применять нейропедагогические методы и приемы в образовательной деятельности с учетом возрастных и индивидуальных особенностей детей", "разрабатывать и адаптировать нейропедагогические материалы для обучения и развития детей"], "abilities": ["использования приемов и техник нейропедагогики в работе с дошкольниками"]}', NULL, 1, 19);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ОРГАНИЗАЦИЯ МУЗЕЙНОГО УГОЛКА В ДОУ В КОНТЕКСТЕ РЕАЛИЗАЦИИ ФГОС И ФОП ДО: ОТ ЗАМЫСЛА ДО РЕАЛИЗАЦИИ', 'organizatsiya-muzeynogo-ugolka-v-dou-v-kontekste-realizatsii-fgos-i-fop-do-ot-zamysla-do-realizatsii', 'Курс для тех, кто хочет овладеть навыками организации музейного уголка в ДОУ и использовать музейную педагогику в образовательном процессе в соответствии с ФГОС и ФОП ДО.', 'Воспитатель \nОвладеете навыками организации музейного уголка в ДОУ, освоите методические подходы к использованию музейной педагогики в образовательном процессе, научитесь проводить работу с экспозициями для развития детей дошкольного возраста.\nСтарший воспитатель (методист) \nРазберетесь в организации музейного уголка в соответствии с ФГОС и ФОП ДО, получите методические инструменты для сопровождения педагогов, позаимствуете успешные практики использования музейного пространства в образовательном процессе ДОУ.', 'Дошкольное образование', 36, 'kpk', 'заочная с применением дистанционных образовательных технологий', 4800, '[{"number": 1, "title": "Роль музейной педагогики в образовательном процессе дошкольного образовательного учреждения"}, {"number": 2, "title": "Организация музейного уголка в ДОУ"}, {"number": 3, "title": "Методические аспекты организации работы с экспозициями музейного уголка в ДОУ"}, {"number": 4, "title": "Успешные практики использования музейного уголка в образовательном процессе ДОУ: рекомендации"}]', '{"knowledge": ["основных принципов музейной педагогики и способов их реализации в работе с детьми дошкольного возраста", "нормативно-правовых оснований, регламентирующих деятельность музейного уголка в ДОУ", "принципов и этапов проектирования музейного уголка", "принципов построения экспозиции музейного уголка в ДОУ"], "skills": ["организовывать деятельность музейного уголка в условиях реализации ФГОС ДО; использовать музейный уголок в образовательном процессе ДОУ", "использовать приемы включения дошкольников в работу музейного уголка"], "abilities": ["владения методиками организации работы музейного уголка"]}', NULL, 1, 20);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ОСНОВЫ ПРЕПОДАВАНИЯ ФИНАНСОВОЙ ГРАМОТНОСТИ В ДОШКОЛЬНЫХ ОБРАЗОВАТЕЛЬНЫХ УЧРЕЖДЕНИЯХ', 'osnovy-prepodavaniya-finansovoy-gramotnosti-v-doshkolnyh-obrazovatelnyh-uchrezhdeniyah', 'Курс для педагогов, желающих формировать основы финансовой грамотности у дошкольников.', 'Воспитатель\nИзучите основы финансовой грамотности для дошкольников и научитесь создавать увлекательные занятия, формирующие у детей первые экономические представления.\nМетодист\nРазберитесь в методиках преподавания финансовой грамотности в ДОУ и получите инструменты для методической поддержки педагогов в развитии экономических навыков у детей.', 'Дошкольное образование', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 7200, '[{"number": 1, "title": "Финансовая грамотность – понятие, роль, необходимость формирования финансовой грамотности у граждан"}, {"number": 2, "title": "Нормативно-правовые основы формирования финансовой грамотности дошкольников в условиях реализации ФГОС ДО"}, {"number": 3, "title": "Современные подходы к разработке и проведению программ повышения финансовой грамотности в дошкольных учреждениях (на основе опыта СФК «Лесная биржа»)"}]', '{"knowledge": ["роли финансовой грамотности в жизни человека", "целей формирования финансовой грамотности у дошкольников", "основных компонентов программ и госпрограмм по финансовой грамотности в России и за рубежом", "основных навыков и тем, необходимых для формирования у дошкольников основ финансовой грамотности", "нормативно-правовых основ формирования финансовой грамотности дошкольников в условиях реализации ФГОС ДО"], "skills": ["разрабатывать полноценное занятие по финансовой грамотности", "взаимодействовать с родителями по вопросам финансовой грамотности дошкольников"], "abilities": ["принципами построения занятий для дошкольников по финансовой грамотности"]}', NULL, 1, 21);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('МУЛЬТСТУДИЯ КАК ИННОВАЦИОННЫЙ МЕТОД РАЗВИТИЯ ДОШКОЛЬНИКОВ', 'multstudiya-kak-innovatsionnyy-metod-razvitiya-doshkolnikov', 'Курс для воспитателей, желающих использовать мультстудию как практико-ориентированный инструмент развития дошкольников в разных видах деятельности.', 'Воспитатель\nИзучите различные техники мультипликации, научитесь создавать с детьми собственные мультфильмы.', 'Дошкольное образование', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 7500, '[{"number": 1, "title": "Актуальные проблемы и направления совершенствования дошкольного образования в соответствии с требованиями ФГОС ДО"}, {"number": 2, "title": "Методика организации и сопровождения мультстудии в ДОУ"}, {"number": 3, "title": "Технологии создания мультфильмов для детей дошкольного возраста"}, {"number": 4, "title": "Цифровые компетенции современного педагога"}]', '{"knowledge": ["нормативно-правовых и методологических основ дошкольного образования в условиях реализации ФГОС ДО", "содержания и технологий создания анимационных проектов", "организационно-методических основ сопровождения мультстудии в условиях ДОО"], "skills": ["использовать технологии создания анимационных проектов для развития детей дошкольного возраста", "проектировать и организовывать деятельность мультстудии в условиях ДОО", "сопровождать педагогический процесс мультстудии, обеспечивая развитие детей в разных видах деятельности"], "abilities": ["методика организации и сопровождения деятельности мультстудии для дошкольников"]}', NULL, 1, 22);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ОРГАНИЗАЦИЯ ПРОФИЛАКТИКИ ДОРОЖНО-ТРАНСПОРТНОГО ТРАВМАТИЗМА В ДЕТСКОМ САДУ', 'organizatsiya-profilaktiki-dorozhno-transportnogo-travmatizma-v-detskom-sadu', 'Курс для педагогов, желающий качественно организовывать профилактику дорожно-транспортного травматизма среди дошкольников в детском саду.', 'Воспитатель\nОсвойте методы обучения дошкольников безопасному поведению на дорогах и профилактике дорожно-транспортного травматизма\nМетодист\nРазвивайте навыки организации и координации профилактических мероприятий по безопасности дорожного движения в детском саду.', 'Дошкольное образование', 16, 'kpk', 'заочная с применением дистанционных образовательных технологий', 3750, '[{"number": 1, "title": "Методика обучение ПДД детей дошкольного возраста"}, {"number": 2, "title": "Формы работы с дошкольниками по профилактике ДТТ"}, {"number": 3, "title": "Работа с родителями детей дошкольного возраста по профилактике ДТТ"}]', '{"knowledge": ["методик и приемов обучения правилам дорожного движения (ПДД) для детей дошкольного возраста", "федеральных образовательных стандартов и требований по профилактике дорожно-транспортного травматизма (ДТТ)", "принципов и требований к созданию развивающей предметно-пространственной среды", "эффективных форм взаимодействия с родителями и социальными партнерами"], "skills": ["применять различные методические подходы в зависимости от возрастных особенностей детей", "разрабатывать и проводить занятия, игры и другие мероприятия, направленные на обучение ПДД", "координировать работу родительского патруля для повышения безопасности дорожного движения вблизи детских садов"], "abilities": ["организации профилактики дорожно-транспортного травматизма в детском саду"]}', NULL, 1, 23);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ИКТ В РАБОТЕ ПЕДАГОГА ДОШКОЛЬНОГО ОБРАЗОВАНИЯ: ВНЕДРЕНИЕ И ПРИМЕНЕНИЕ В СООТВЕТСТВИИ С ФГОС ДО', 'ikt-v-rabote-pedagoga-doshkolnogo-obrazovaniya-vnedrenie-i-primenenie-v-sootvetstvii-s-fgos-do', '', '', '', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 0, NULL, NULL, NULL, 1, 24);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('СОВРЕМЕННЫЕ ПОДХОДЫ К РЕАЛИЗАЦИИ ОБРАЗОВАТЕЛЬНОЙ ПРОГРАММЫ В ДОУ: ТЕХНОЛОГИЯ ГИБКОГО ПЛАНИРОВАНИЯ', 'sovremennye-podhody-k-realizatsii-obrazovatelnoy-programmy-v-dou-tehnologiya-gibkogo-planirovaniya', 'Курс для воспитателей, желающих проектировать образовательный путь не по готовому маршруту, а вместе с детьми.', 'Воспитатель\nНаучитесь легко и гибко проектировать образовательный процесс, отталкиваясь от интересов детей. Получите готовые инструменты (шаблоны, алгоритмы) для того, чтобы каждый день в группе был увлекательным исследованием, а ваша работа стала более творческой и осмысленной.\nСтарший воспитатель\nПолучите целостную методологию и практические инструменты для организации работы педагогического коллектива по внедрению гибкого планирования.\nМетодист\nСможете разработать и внедрить на уровне детского сада современную модель планирования, соответствующую принципам ФГОС ДО и ФОП ДО.', 'Дошкольное образование', 36, 'kpk', 'заочная с применением дистанционных образовательных технологий', 4800, '[{"number": 1, "title": "Нормативно-правовое основание для реализации технологии гибкого планирования"}, {"number": 2, "title": "Роль педагога и начальные этапы планирования"}, {"number": 3, "title": "Инструментарий и технологии гибкого планирования"}, {"number": 4, "title": "Внедрение технологии и оценка результатов"}, {"number": 5, "title": "Цифровые компетенции современного педагога"}]', '{"knowledge": ["нормативных оснований (ФГОС ДО, ФОП ДО) гибкого подхода к планированию образовательной деятельности в ДОО", "принципиальных отличий, преимуществ и рисков гибкого (событийного) и традиционного календарно-тематического планирования", "современных техник и инструментов гибкого планирования: метод проектных «паутинок», технологию «утреннего круга» и центров развития"], "skills": ["осуществлять целенаправленное педагогическое наблюдение для выявления и фиксации актуальных интересов, вопросов и образовательных ситуаций в группе", "проектировать тематические «паутинки» и гибкие недельные планы образовательной деятельности, интегрируя детские инициативы с задачами образовательной программы", "организовывать работу центров активности и модифицировать предметно-пространственную среду группы в соответствии с текущими темами и интересами детей"], "abilities": ["проектирование образовательного процесса как динамичной, развивающейся системы, а не как жесткого сценария", "владение технологией организации краткосрочных образовательных проектов, инициированных детьми", "владение методом рефлексии собственной профессиональной позиции и анализа эффективности применяемых педагогических инструментов"]}', NULL, 1, 25);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ОРГАНИЗАЦИЯ ДЕЯТЕЛЬНОСТИ ИНСТРУКТОРА ПО ФИЗИЧЕСКОЙ КУЛЬТУРЕ В ДОО В УСЛОВИЯХ РЕАЛИЗАЦИИ ФОП ДО И ФГОС ДО', 'organizatsiya-deyatelnosti-instruktora-po-fizicheskoy-kulture-v-doo-v-usloviyah-realizatsii-fop-do-i-fgos-do', 'Курс для тех, кто приучает детей дошкольного возраста к физической культуре и желает применять в работе новые методы и технологии.', 'Инструктор по физической культуре \nОвладеете инновационными подходами в организации деятельности по физической культуре в ДОУ, освоите здоровьесберегающие технологии и методику проведения подвижных игр для развития физических способностей детей, научитесь моделировать образовательный процесс в соответствии с требованиями ФГОС и ФОП ДО.\nПедагог дополнительного образования\nРазберетесь в теоретических основах педагогики и психологии развития дошкольников, получите инструменты для планирования физкультурной деятельности, овладеете технологиями здоровьесбережения и практическими методиками для повышения эффективности занятий.', 'Дошкольное образование', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 6225, '[{"number": 1, "title": "Нормативное обеспечение дошкольного образования"}, {"number": 2, "title": "Особенности педагогики и психологии развития детей дошкольного возраста"}, {"number": 3, "title": "Образовательный процесс по физической культуре в ДОУ"}, {"number": 4, "title": "Моделирование образовательного процесса по физической культуре в ДОУ на основе ФГОС"}, {"number": 5, "title": "Здоровьесберегающие технологии в соответствие с требованиями ФГОС ДО"}]', '{"knowledge": ["нормативно-правовых основ ФГОС дошкольного образования и организационно-планирующей деятельности инструктора физической культуры", "специфики дошкольного образования и особенностей организации работы с детьми раннего и дошкольного возраста", "основных психологических подходов и основ дошкольной педагогики, включая классические системы дошкольного воспитания"], "skills": ["выбирать и реализовывать образовательные программы в условиях реализации ФГОС и ФОП ДО", "применять на практике новые методы, приемы и технологии физического воспитания дошкольников", "организовывать контроль за реализацией программы физической культуры"], "abilities": ["владеть новыми методами, приемами и технологиями физического воспитания дошкольников"]}', NULL, 1, 26);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('РАЗВИТИЕ ПРОФЕССИОНАЛЬНОЙ КОМПЕТЕНТНОСТИ УЧИТЕЛЯ ПО ФОРМИРОВАНИЮ ФУНКЦИОНАЛЬНОЙ ГРАМОТНОСТИ ОБУЧАЮЩИХСЯ', 'razvitie-professionalnoy-kompetentnosti-uchitelya-po-formirovaniyu-funktsionalnoy-gramotnosti-obuchayuschihsya', 'Курс для педагогов, желающих владеть всем комплексом знаний о функциональной грамотности и научиться разрабатывать индивидуальные стратегии обучения.', 'Учитель-предметник\nОсвоите методы развития функциональной грамотности, направленные на применение знаний в реальных жизненных ситуациях.\nЗаместитель директора, методист\nУзнаете, как разработать систему оценки и мониторинга функциональной грамотности в школе.', 'Школа', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 6750, '[{"number": 1, "title": "Функциональная грамотность – сущность, структура, содержание. Актуальность формирования в условиях изменений социальной ситуации развития"}, {"number": 2, "title": "Методические основы формирования и развития функциональной грамотности обучающихся ОО"}, {"number": 3, "title": "Система оценки уровня сформированности функциональной грамотности обучающихся ОО"}]', '{"knowledge": ["основ функциональной грамотности, компонентов функциональной грамотности", "факторов, влияющих на развитие функциональной грамотности школьников", "основных методов и форм, способствующих развитию функциональной грамотности"], "skills": ["оценивать уровень сформированности функциональной грамотности у обучающихся", "организовывать и проводить мониторинги процесса формирования и развития функциональной грамотности у обучающихся", "прогнозировать результаты деятельности, направленной на формирование и развитие функциональной грамотности обучающихся"], "abilities": ["владеть методами, техниками, инструментами оценивания, формирования, мониторинга сформированности функциональной грамотности у обучающихся"]}', NULL, 1, 27);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('КОНСУЛЬТИРОВАНИЕ РОДИТЕЛЕЙ С ИСПОЛЬЗОВАНИЕМ СОВРЕМЕННОГО ФОРМАТА ВЗАИМОДЕЙСТВИЯ', 'konsultirovanie-roditeley-s-ispolzovaniem-sovremennogo-formata-vzaimodeystviya', 'Курс для педагогов, которые хотят грамотно организовывать консультирование родителей обучающихся при помощи современного формата взаимодействия.', 'Классный руководитель\nНаучитесь проводить эффективные онлайн- и офлайн-консультации и родительские собрания, которые способствуют улучшению коммуникации с родителями и вовлечению их в образовательный процесс.\nПедагог-психолог\nОсвоите техники конструктивного диалога с родителями, включая работу с трудными запросами и конфликтными ситуациями.\nСоциальный педагог\nОсвоите методы работы с «трудными» семьями, включая случаи социального неблагополучия.', 'Школа', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 9300, '[{"number": 1, "title": "Консультирование. Сущность, формы, виды. Цели и задачи консультирования родителей"}, {"number": 2, "title": "Консультирование родителей с опорой на особенности возраста"}, {"number": 3, "title": "Психологическое здоровье как ключевое понятие психологической службы, определяющее работу с родителями"}, {"number": 4, "title": "Этические проблемы в психологическом консультирование"}, {"number": 5, "title": "Этапы, методы, приемы и техники личностного консультирования в психолого-педагогической практике"}, {"number": 6, "title": "Консультирование родителей: современные форматы взаимодействия"}]', '{"knowledge": ["современных теорий и методов консультирования", "приемов организации совместной и индивидуальной деятельности обучающихся в соответствии с возрастными нормами их развития", "этических норм организации и проведения консультативной работы"], "skills": ["проводить индивидуальные и групповые консультации родителей обучающихся по вопросам обучения, развития, воспитания, взаимоотношений со взрослыми и сверстниками"], "abilities": ["владения способами эффективного консультирования родителей с использованием современного формата взаимодействия"]}', NULL, 1, 28);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('РАБОТА КЛАССНОГО РУКОВОДИТЕЛЯ ПО ОРГАНИЗАЦИИ ВЗАИМОДЕЙСТВИЯ СЕМЬИ И ШКОЛЫ', 'rabota-klassnogo-rukovoditelya-po-organizatsii-vzaimodeystviya-semi-i-shkoly', 'Курс для классных руководителей, желающих усовершенствовать навыки конструктивного взаимодействия и сотрудничества с родителями обучающихся по вопросам воспитания в школе.', 'Классный руководитель\nНаучитесь выстраивать эффективную коммуникацию с родителями для совместного решения образовательных и воспитательных задач, используя современные цифровые инструменты.\nТьютор\nОсвоите технологии проведения родительских собраний и индивидуальных консультаций, направленных на повышение вовлеченности семей в школьную жизнь.', 'Школа', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 6675, '[{"number": 1, "title": "Значение и сущность воспитательной работы в современных условиях"}, {"number": 2, "title": "Нормативно-правовое регулирование воспитательной работы в школе"}, {"number": 3, "title": "Основные направления деятельности классного руководителя в условиях реализации ФГОС"}, {"number": 4, "title": "Современные практики в работе классных руководителей по взаимодействию с родителями учащихся"}, {"number": 5, "title": "Основные направления и формы организации воспитательной работы на современном этапе"}, {"number": 6, "title": "Гражданско-патриотическое воспитание учащихся в условиях реализации ФГОС"}]', '{"knowledge": ["основных направлений работы классного руководителя в рамках обновленных ФГОС", "актуальных изменений государственной политики в области воспитания", "современных эффективных форм взаимодействия классного руководителя с родителями"], "skills": ["осуществлять воспитательную деятельность с учетом государственной повестки в сфере воспитания", "выстраивать конструктивную коммуникацию с родителями обучающихся по вопросам воспитания в школе", "организовывать и проводить родительские собрания"], "abilities": ["конструктивного взаимодействия с родителями обучающихся в процессе решения задач воспитания"]}', NULL, 1, 29);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('СОВРЕМЕННЫЕ ПОДХОДЫ И ТЕХНОЛОГИИ ОРГАНИЗАЦИИ ДОПОЛНИТЕЛЬНОГО ОБРАЗОВАНИЯ ДЕТЕЙ', 'sovremennye-podhody-i-tehnologii-organizatsii-dopolnitelnogo-obrazovaniya-detey', 'Курс для тех , кто хочет создавать по-настоящему увлекательные и востребованные программы дополнительного образования для детей, применяя современные методологические подходы и технологии.', 'Педагог дополнительного образования\nОсвоите современные методы и приемы организации дополнительного образования детей. Программа направлена на развитие практических навыков проектирования персонализированных образовательных программ.', 'Школа , Дошкольное образование', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 6675, '[{"number": 1, "title": "Государственная политика в сфере дополнительного образования детей"}, {"number": 2, "title": "Проектирование и разработка рабочей программы дополнительного образования детей"}, {"number": 3, "title": "Педагогический дизайн и современные образовательные технологии"}, {"number": 4, "title": "Формирование гибких компетенций"}, {"number": 5, "title": "Инклюзивные практики в дополнительном образовании"}]', '{"knowledge": ["нормативно-правовых основ деятельности в сфере дополнительного образования детей, структуры и требований профессионального стандарта", "теоретических основ и принципов педагогического дизайна, проектного обучения, геймификации, STEM-подхода", "методов и технологий формирования гибких навыков и их интеграции в содержание программ дополнительного образования"], "skills": ["проектировать и разрабатывать рабочую программу дополнительного образования, используя современные подходы", "корректировать рабочую программу дополнительного образования с учетом потребностей обучающихся", "применять на практике современные образовательные технологии для достижения планируемых результатов"], "abilities": ["проектирования образовательного процесса", "мотивации и удержания интереса обучающихся на различных этапах занятия", "разработки и реализации индивидуальных образовательных маршрутов"]}', NULL, 1, 30);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('МЕТОДИКА И ПРАКТИКА ОБРАЗОВАТЕЛЬНОЙ ДЕЯТЕЛЬНОСТИ С ДЕТЬМИ С ОВЗ В ДОО', 'metodika-i-praktika-obrazovatelnoy-deyatelnosti-s-detmi-s-ovz-v-doo', 'Курс для тех, кто желает разнообразить свои методики и практики для обеспечения каждому ребенку качественного уровня образования, адекватного имеющимся у него возможностям.', 'Воспитатель\nУглубите знания и практические навыки работы с детьми с ОВЗ, чтобы создавать инклюзивную и поддерживающую образовательную среду.\nПсихолог\nПовысите компетенции по психолого-педагогическому сопровождению дошкольников с ОВЗ для их успешной адаптации и развития.', 'Дошкольное образование, Специальное образование', 36, 'kpk', 'заочная с применением дистанционных образовательных технологий', 3000, '[{"number": 1, "title": "Входной контроль"}, {"number": 2, "title": "Нормативно-правовые основы функционирования дошкольных образовательных организаций, обучающих детей с ОВЗ"}, {"number": 3, "title": "Программа коррекционно-развивающей работы с детьми с ограниченными возможностями здоровья"}, {"number": 4, "title": "Дифференцированные технологии инклюзивного образования в ДОО. Практики образовательной деятельности с детьми ОВЗ"}, {"number": 5, "title": "Механизмы и структурная организация психолого-педагогического сопровождения детей с ОВЗ в дошкольных образовательных организациях"}]', '{"knowledge": ["специальных технологий и методов работы с детьми с ОВЗ", "принципов отбора технологий и методов, приемов и средств коррекционно-образовательной деятельности"], "skills": ["выбирать и применять методики и практики коррекционнообразовательной деятельности с детьми с ОВЗ в дошкольных образовательных организациях"], "abilities": ["владеть навыками для составления программы коррекционно-развивающей работы с детьми с ограниченными возможностями здоровья"]}', NULL, 1, 31);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('НЕЙРОПОДХОД В РАБОТЕ ЛОГОПЕДА', 'neyropodhod-v-rabote-logopeda', 'Курс для практикующих логопедов, которые желают улучшить результаты осуществляемой коррекционной работы посредством включения технологий нейропсихологии.', 'Логопед\nОвладеете нейропсихологическими приемами диагностики и коррекции, освоите технологии нейростимуляции для повышения эффективности логопедической работы, научитесь развивать психические функции детей на занятиях.\nЛогопед-дефектолог (специалист инклюзивного образования) \nОбновите знания о нейропсихологических подходах в коррекции речевых нарушений, научитесь учитывать возможные дефициты работы мозга при составлении программ развития, освоите комплексные методики для работы с детьми, имеющими разные нарушения развития.', 'Специальное образование', 36, 'kpk', 'заочная с применением дистанционных образовательных технологий', 4800, '[{"number": 1, "title": "Основы нейропсихологии"}, {"number": 2, "title": "Нейропсихологические приемы диагностики и коррекции в логопедической работе"}, {"number": 3, "title": "Технологии повышения эффективности логопедической работы через включение приемов нейростимуляции"}, {"number": 4, "title": "Развитие психических функций на логопедических занятиях (внимание, память, мышление)"}]', '{"knowledge": ["основных принципов строения мозга и проявлений его дефицитов", "нейропсихологического подхода на этапе диагностики", "технологий повышения эффективности логопедической работы через включение приемов нейростимуляции"], "skills": ["ориентироваться в терминологии нейропсихологии и более глубоко понимать анатомию ЦНС", "включать в логопедическую диагностику элементы нейропсихологической диагностики", "использовать приемы нейростимуляции в логопедической работе при работе с артикуляционной моторикой, фонематическим слухом, речевым дыханием, звукопроизношением и дифференциацией звуков", "включать нейроупражнения для развития внимания, памяти и мышления в логопедические занятия"], "abilities": ["применения нейроподхода в логопедической работе с целью совершенствования результата коррекции речи"]}', NULL, 1, 32);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ОСНОВЫ ЛОГОПЕДИЧЕСКОЙ ТЕОРИИ И ПРАКТИКИ: КОРРЕКЦИЯ РЕЧЕВЫХ НАРУШЕНИЙ ДЕТЕЙ ДОШКОЛЬНОГО И МЛАДШЕГО ШКОЛЬНОГО ВОЗРАСТА', 'osnovy-logopedicheskoy-teorii-i-praktiki-korrektsiya-rechevyh-narusheniy-detey-doshkolnogo-i-mladshego-shkolnogo-vozrast', 'Курс для специалистов с опытом до 3 лет, кто хочет систематизировать знания по диагностике речевых нарушений, а также их коррекции при диагнозах дислалия, дизартрия, алалия, дисграфия и дислексия. Узнать больше про логопедический массаж и научиться работать онлайн.', 'Практикующий логопед (начинающий) \nСистематизируете знания по диагностике речевых нарушений, освоите методики коррекции при дислалии, дизартрии, алалии, дисграфии и дислексии, овладеете техниками логопедического массажа и навыками онлайн-консультирования.\nЛогопед-дефектолог \nУглубите теоретические и практические знания по коррекционной работе с детьми разных возрастов, получите инструменты для работы с различными видами речевых нарушений, научитесь применять логопедический массаж в своей практике.', 'Специальное образование', 144, 'kpk', 'заочная с применением дистанционных образовательных технологий', 21000, '[{"number": 1, "title": "Библиотека логопеда"}, {"number": 2, "title": "Продвижение Логопеда в социальных сетях"}]', '{"knowledge": ["основ логопедической диагностики", "особенностей постановки звуков у детей", "особенностей работы с дисграфией и дислексией, а также методикой запуска речи", "секретов работы онлайн"], "skills": ["проводить логопедическую диагностику", "корректировать нарушения звукопроизношения у детей", "запускать речь неговорящим детям"], "abilities": ["диагностирования и коррекционной работы офлайн и онлайн"]}', NULL, 1, 33);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('МЕТОДИКА ПРЕПОДАВАНИЯ ПРЕДМЕТА "ТРУД (ТЕХНОЛОГИЯ)" В СООТВЕТСТВИИ С ОБНОВЛЕННЫМ ФГОС НОО', 'metodika-prepodavaniya-predmeta-trud-tehnologiya-v-sootvetstvii-s-obnovlennym-fgos-noo', 'Курс будет полезен учителям начальных классов, которые хотят разобраться в особенностях современных подходов в обучении предмета «Труд (технология)», основанных на требованиях нормативных документов.', 'Учитель начальных классов\nОвладеете профессиональными компетенциями в методике преподавания предмета «Труд (технология)»', 'Школа', 36, 'kpk', 'заочная с применением дистанционных образовательных технологий', 4800, '[{"number": 1, "title": "Нормативно-правовое обеспечение предмета «Труд (технология)» в соответствии с ФГОС и ФОП НОО"}, {"number": 2, "title": "Содержание и организация обучения предмета «Труд (технология)» в начальных классах"}, {"number": 3, "title": "Оценка достижений учащихся на уроке «Труд (технология)»"}]', '{"knowledge": ["целей и задач обучения, особенностей современных подходов в обучении предмета «Труд (технология)», основанных на требованиях нормативных документов", "основополагающих принципов проектирования современного урока в области достижения образовательных результатов ФГОС", "основных методик преподавания предмета «Труд (технология)»"], "skills": ["планировать и организовывать образовательный процесс на основе требований ФГОС", "планировать и организовывать учебную деятельность обучающихся на уроке в аспекте достижения предметных и метапредметных результатов", "использовать возможности образовательной среды для достижения личностных, метапредметных и предметных результатов обучения и обеспечения качества учебно-воспитательного процесса"], "abilities": ["владения эффективными методами и приемами обучения"]}', NULL, 1, 34);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ОБЕСПЕЧЕНИЕ ТЕХНОЛОГИЧЕСКОГО СУВЕРЕНИТЕТА РОССИЙСКОЙ ФЕДЕРАЦИИ: ФОРМИРОВАНИЕ И РАЗВИТИЕ ЕСТЕСТВЕННОНАУЧНОЙ ГРАМОТНОСТИ УЧАЩИХСЯ', 'obespechenie-tehnologicheskogo-suvereniteta-rossiyskoy-federatsii-formirovanie-i-razvitie-estestvennonauchnoy-gramotnost', 'Курс для  тех, кто хочет включиться в решение государственных задач по обеспечению технологического суверенитета страны и освоить методику формирования  естественнонаучной грамотности у школьников.', 'Учитель-предметник:\nВстроит контекст технологического суверенитета в совместную деятельность с обучающимися', 'Школа', 36, 'kpk', 'заочная с применением дистанционных образовательных технологий', 4800, '[{"number": 1, "title": "Роль науки и образования в обеспечении технологического суверенитета страны"}, {"number": 2, "title": "Развитие естественнонаучной грамотности учащихся как условие обеспечения технологического суверенитета РФ"}, {"number": 3, "title": "Методические подходы к формированию естественнонаучной грамотности"}]', '{"knowledge": ["значений понятий: технологический суверенитет, функциональная грамотность, естественнонаучная грамотность", "роли системы образования в обеспечении технологического суверенитета страны", "методических подходов к формированию естественнонаучной грамотности у школьников"], "skills": ["выстраивать работу по формированию естественнонаучной грамотности в рамках преподавания предметов естественнонаучного цикла", "разрабатывать задания для диагностических работ по естественнонаучной грамотности"], "abilities": ["оценивания сформированности естественнонаучной грамотности у обучающихся", "создания диагностических работ (заданий) по естественнонаучной грамотности"]}', NULL, 1, 35);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('СОВРЕМЕННЫЕ ТРЕБОВАНИЯ К ДЕЯТЕЛЬНОСТИ ПЕДАГОГА-ПСИХОЛОГА В СООТВЕТСТВИИ С ФГОС: СОЗДАНИЕ ПСИХОЛОГИЧЕСКИ БЕЗОПАСНОЙ ОБРАЗОВАТЕЛЬНОЙ СРЕДЫ', 'sovremennye-trebovaniya-k-deyatelnosti-pedagoga-psihologa-v-sootvetstvii-s-fgos-sozdanie-psihologicheski-bezopasnoy-obra', 'Курс для педагогов-психологов, которые хотят выстроить эффективную работу со всеми участниками образовательного процесса для создания психологически безопасной образовательной среды в школе.', 'Педагог-психолог \nСможете оказать психологическое консультирование участникам образовательного процесса (учащимся, родителям, педагогам)', 'Школа', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 6225, '[{"number": 1, "title": "Нормативно-правовая база организации деятельности педагога-психолога"}, {"number": 2, "title": "Деятельность педагога-психолога образовательной организации по созданию психологически безопасной образовательной среды"}, {"number": 3, "title": "Профилактическая работа педагога-психолога в образовательной организации"}, {"number": 4, "title": "Психологическое консультирование участников образовательного процесса"}]', '{"knowledge": ["основных направлений деятельности педагога-психолога образовательной организации по формированию психологически безопасной образовательной среды", "причин и характера проявления рискованного, зависимого и деструктивного поведения детей и подростков в образовательной организации", "особенностей профилактической работы педагога-психолога в образовательной организации"], "skills": ["проводить оценку психологической безопасности образовательной среды и интерпретировать ее результаты", "планировать работу по профилактике возникновения рискованного, зависимого и деструктивного поведения детей и подростков в образовательной организации", "проводить консультирование педагогических работников, обучающихся и родителей (законных представителей) по вопросам образовательной деятельности"], "abilities": ["разработки и проведения профилактических, диагностических, развивающих мероприятий в образовательной организации", "консультирования педагогических работников, обучающихся и родителей (законных представителей) по вопросам образовательной деятельности"]}', NULL, 1, 36);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ДЕЯТЕЛЬНОСТЬ КЛАССНОГО РУКОВОДИТЕЛЯ В ОБЛАСТИ ВОСПИТАНИЯ ОБУЧАЮЩИХСЯ В СООТВЕТСТВИИ С ФГОС', 'deyatelnost-klassnogo-rukovoditelya-v-oblasti-vospitaniya-obuchayuschihsya-v-sootvetstvii-s-fgos', 'Курс для классных руководителей, которые желают найти современные подходы к организации педагогической деятельности в области воспитания и социализации.', 'Классный руководитель\nСможете эффективно организовать воспитательную деятельность в соответствии с требованиями ФГОС, используя актуальные методические подходы', 'Школа', 36, 'kpk', 'заочная с применением дистанционных образовательных технологий', 4800, '[{"number": 1, "title": "Нормативные и теоретико-методологические основы классного руководства в условиях реализации ФГОС"}, {"number": 2, "title": "Деятельность классного руководителя в решении задач воспитания обучающихся"}, {"number": 3, "title": "Методическое обеспечение воспитательной деятельности классного руководителя"}, {"number": 4, "title": "Цифровые компетенции современного педагога"}]', '{"knowledge": ["функций современного классного руководителя и его роли в воспитании и социализации обучающихся", "методов воспитания и проектирования воспитательных технологий", "основных положений модернизации воспитательной деятельности образовательных организаций"], "skills": ["применять современные образовательные технологии и формы воспитательной работы", "применять эффективные методики воспитательной работы и социализации обучающихся"]}', NULL, 1, 37);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('СОВРЕМЕННЫЕ ТЕХНОЛОГИИ РАБОТЫ С ОДАРЕННЫМИ ДЕТЬМИ И ПОДГОТОВКА ИХ К ОЛИМПИАДАМ', 'sovremennye-tehnologii-raboty-s-odarennymi-detmi-i-podgotovka-ih-k-olimpiadam', 'Для учителей, которые хотят знать о феномене детской одаренности, ее особенностях выявления и организовывать работу по подготовке одаренных детей.', 'Учитель-предметник\nНаучитесь работать с одаренными и высокомотивированными учениками, сможете выстраивать индивидуальные траектории развития детей.\nРуководители центров работы с одаренными детьми\nОсвоите стратегии выявления и поддержки талантливых школьников, включая организацию конкурсов и проектной деятельности.', 'Школа', 36, 'kpk', 'заочная с применением дистанционных образовательных технологий', 3750, '[{"number": 1, "title": "Одаренные дети: теоретическая основа. Особенности выявления одаренных детей"}, {"number": 2, "title": "Профессиональная компетентность педагога и организация работы с одаренными детьми. Подготовка одаренных детей к олимпиадам"}, {"number": 3, "title": "Взаимодействие с родителями при работе с одаренным ребенком"}]', '{"knowledge": ["понятий «одаренность» и «одаренные дети»", "признаков одаренных детей", "видов одаренных детей", "особенностей и проблем выявления одаренных детей"], "skills": ["выстраивать работу (подбирать формы, методы, технологии) по взаимодействию и поддержке одаренных детей", "выстраивать работу по подготовке одаренных детей к олимпиадам", "анализировать свою профессиональную деятельность при работе с одаренными детьми"], "abilities": ["владеть навыками подбора эффективных форм, методов и технологий для подготовки одаренных детей к олимпиадам различного уровня"]}', NULL, 1, 38);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ЛОГОПЕДИЧЕСКОЕ СОПРОВОЖДЕНИЕ И КОРРЕКЦИОННАЯ РАБОТА С ОБУЧАЮЩИМИСЯ С ТЯЖЕЛЫМИ НАРУШЕНИЯМИ РЕЧИ В УСЛОВИЯХ РЕАЛИЗАЦИИ ФГОС', 'logopedicheskoe-soprovozhdenie-i-korrektsionnaya-rabota-s-obuchayuschimisya-s-tyazhelymi-narusheniyami-rechi-v-usloviyah', '', '', '', 144, 'kpk', 'заочная с применением дистанционных образовательных технологий', 0, NULL, NULL, NULL, 1, 39);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ФОРМИРОВАНИЕ ФУНКЦИОНАЛЬНОЙ ГРАМОТНОСТИ МЛАДШИХ ШКОЛЬНИКОВ В УСЛОВИЯХ РЕАЛИЗАЦИИ ФГОС НОО', 'formirovanie-funktsionalnoy-gramotnosti-mladshih-shkolnikov-v-usloviyah-realizatsii-fgos-noo', 'Курс для педагогов, которые хотят обучиться современным методикам формирования функциональной грамотности с последующим применением на практике в работе с младшими школьниками.', 'Учитель начальных классов\nПолучите практические инструменты для развития у детей навыков чтения, математической и естественнонаучной грамотности в соответствии с ФГОС.\nЗаместитель директора\nНаучитесь выстраивать систему мониторинга развития функциональной грамотности у обучающихся для повышения образовательных результатов школы.', 'Школа', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 6750, '[{"number": 1, "title": "Функциональная грамотность – сущность, структура, содержание. Актуальность формирования в условиях изменений социальной ситуации развития"}, {"number": 2, "title": "Содержание функциональной грамотности в начальной школе"}, {"number": 3, "title": "Формирование читательской грамотности"}, {"number": 4, "title": "Формирование математической грамотности"}, {"number": 5, "title": "Формирование естественнонаучной грамотности"}, {"number": 6, "title": "Формирование финансовой грамотности"}, {"number": 7, "title": "Оценка функциональной грамотности школьников"}]', '{"knowledge": ["понятий функциональной грамотности", "факторов, влияющих на развитие функциональной грамотности школьников", "основных методов и форм, способствующих развитию функциональной грамотности"], "skills": ["включать задания на формирование функциональной грамотности в учебный процесс", "создавать задания для оценки определенного типа функциональной грамотности", "создавать учебные материалы по своему предмету, направленные на формирование функциональной грамотности школьников"], "abilities": ["владеть методами, техниками, инструментами оценивания, формирования, мониторинга сформированности функциональной грамотности у обучающихся"]}', NULL, 1, 40);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ОРГАНИЗАЦИЯ ОБРАЗОВАТЕЛЬНОГО ПРОЦЕССА В СООТВЕТСТВИИ С ОБНОВЛЕННЫМ ФГОС НОО', 'organizatsiya-obrazovatelnogo-protsessa-v-sootvetstvii-s-obnovlennym-fgos-noo', 'Курс для учителей начальных классов, желающих научиться выстраивать учебный процесс начальной школы в соответствии с актуальными требованиями ФГОС и ФОП НОО.', 'Учитель начальной школы\nУзнаете, как реализовывать федеральный образовательный стандарт в повседневной практике.\nРуководитель, заместитель директора, методист\nНаучитесь выстраивать учебный процесс начальной школы в соответствии с актуальными требованиями ФГОС.', 'Школа', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 6750, '[{"number": 1, "title": "Обновленный Федеральный государственный образовательный стандарт начального общего образования"}, {"number": 2, "title": "Основная образовательная программа начального общего образования"}, {"number": 3, "title": "Структура и содержание урока в соответствии с требованиями ФГОС НОО"}, {"number": 4, "title": "Цифровые компетенции современного педагога"}]', '{"knowledge": ["нормативно-правовых основ реализации и обновления ФГОС НОО", "требований к структуре, результатам и условиям реализации образовательной программы", "принципов формирования ФОП НОО и рабочей программы"], "skills": ["разрабатывать и адаптировать образовательные программы в соответствии с ФГОС", "проектировать разные типы уроков с учётом планируемых результатов", "организовывать учебный процесс на основе системно-деятельностного подхода"], "abilities": ["работы с нормативными документами и методическими материалами", "составления рабочих программ и технологических карт уроков", "использования современных педагогических технологий и диагностических инструментов"]}', NULL, 1, 41);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('МЕДИАЦИЯ: ТЕХНОЛОГИИ И ПРАКТИКИ УПРАВЛЕНИЯ КОНФЛИКТНЫМИ СИТУАЦИЯМИ', 'mediatsiya-tehnologii-i-praktiki-upravleniya-konfliktnymi-situatsiyami', 'Курс для тех, кто желает создать безопасное образовательное пространство, в котором даже очень сложные конфликты могут быть урегулированы конструктивно.', 'Учитель-предметник\nНаучитесь применять технологии медиации для конструктивного разрешения конфликтов между учащимися в классе\nРуководитель\nРеализуете системный подход к управлению конфликтами в образовательной организации', 'Школа', 36, 'kpk', 'заочная с применением дистанционных образовательных технологий', 3750, '[{"number": 1, "title": "Медиация как альтернативный метод разрешения споров"}, {"number": 2, "title": "Модель компетентностного подхода в медиации"}, {"number": 3, "title": "Медиация в образовательных учреждениях"}, {"number": 4, "title": "Технологии современной медиации"}]', '{"knowledge": ["места медиации в системе альтернативного разрешения споров", "правовых оснований медиации и работы медиатора в России", "причин возникновения, структуры и динамики конфликта"], "skills": ["отграничивать медиацию от других альтернативных процедур", "определять медиабельность спора", "вступить в контакт и поддерживать эффективную коммуникацию со сторонами конфликта"], "abilities": ["владеть навыками активного слушания", "владеть навыками разработки необходимых документов, сопровождающих процедуру медиации"]}', NULL, 1, 42);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ДЕЯТЕЛЬНОСТЬ КЛАССНОГО РУКОВОДИТЕЛЯ: ПРОФИЛАКТИКА И ПУТИ ВЫЯВЛЕНИЯ КОНФЛИКТНЫХ СИТУАЦИЙ, БУЛЛИНГА, МОББИНГА И ТРОЛЛИНГА В ОБРАЗОВАТЕЛЬНОЙ ОРГАНИЗАЦИИ', 'deyatelnost-klassnogo-rukovoditelya-profilaktika-i-puti-vyyavleniya-konfliktnyh-situatsiy-bullinga-mobbinga-i-trollinga', 'Курс будет полезен классным руководителям, которые нацелены на формирование безопасной среды в образовательном учреждении, в которой максимально снижено влияние факторов, провоцирующих буллинг, мобинг, троллинг, и сведена к минимуму потребность проявлять агрессию любого рода.', 'Классный руководитель\nНаучитесь распознавать признаки травли, осовоите методы и формы профилактики различных форм насилия в образовательной среде\nПедагог-психолог\nОсвоите техники медиации и алгоритмы работы с агрессорами и жертвами буллинга.\nСоциальный педагог\nИзучите методики для формирования безопасной и комфортной образовательной среды в школе.', 'Школа', 36, 'kpk', 'заочная с применением дистанционных образовательных технологий', 4800, '[{"number": 1, "title": "Буллинг в образовательной организации"}, {"number": 2, "title": "Создание психологически безопасной среды в образовательной организации"}, {"number": 3, "title": "Работа с родителями как один из эффективных методов профилактики и устранения буллинга в образовательной организации"}]', '{"knowledge": ["особенностей проявления детской и подростковой агрессии в воспитательной среде образовательной организации", "разновидностей буллинга (моббинг, троллинг, кибербуллинг, шутинг)", "методов профилактики буллинга в воспитательной среде образовательной организации"], "skills": ["проводить функциональную оценку конфликтных ситуаций для определения реальных целей их возникновения", "разрабатывать планы урегулирования буллинга на основе анализа их структуры, содержания и стадии развития", "применять структурные методы и процедуры работы с конфликтами с учетом интересов сторон"], "abilities": ["использования методов и приемов в деятельности классного руководителя по вопросам буллинга"]}', NULL, 1, 43);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ДЕЯТЕЛЬНОСТЬ КЛАССНОГО РУКОВОДИТЕЛЯ: СОПРОВОЖДЕНИЕ ПРОФЕССИОНАЛЬНОГО САМООПРЕДЕЛЕНИЯ ОБУЧАЮЩИХСЯ', 'deyatelnost-klassnogo-rukovoditelya-soprovozhdenie-professionalnogo-samoopredeleniya-obuchayuschihsya', 'Курс для классных руководителей, желающих разобрать реальные кейсы по профессиональной навигации школьников, которые помогут в профессиональной деятельности.', 'Классный руководитель\nРеализуете профинформирование и профконсультирование обучающихся', 'Школа', 24, 'kpk', 'заочная с применением дистанционных образовательных технологий', 3000, '[{"number": 1, "title": "Приоритетные направления образовательной политики РФ в области профориентационной работы с обучающимися"}, {"number": 2, "title": "Организационные и методические основы профессиональной ориентации школьников"}, {"number": 3, "title": "Особенности профинформирования и профконсультирования"}, {"number": 4, "title": "Разбор кейсов по профессиональной навигации школьников"}]', '{"knowledge": ["цели и задачи деятельности по сопровождению профессионального самоопределения и профессионального выбора школьников", "особенности профинформирования и профконсультирования школьников и их родителей (законных представителей)", "методы и технологии профориентационной работы с обучающимися с ограниченными возможностями здоровья в условиях общеобразовательной организации"], "skills": ["использовать современные подходы, формы и методы профориентации", "организовывать деятельность профориентационной работы с обучающимися с учетом возрастных и индивидуальных особенностей, в том числе для детей с ОВЗ", "профинформировать и профконсультировать родителей (законных представителей)"], "abilities": ["владеть технологиями разработки эффективной модели профессиональной ориентации обучающихся", "владеть навыками проведения работы по подготовке обучающихся к выбору профессии"]}', NULL, 1, 44);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ЦИФРОВАЯ ОБРАЗОВАТЕЛЬНАЯ СРЕДА В ШКОЛЕ: ОРГАНИЗАЦИЯ И УПРАВЛЕНИЕ', 'tsifrovaya-obrazovatelnaya-sreda-v-shkole-organizatsiya-i-upravlenie', 'Курс для руководителей образовательных организаций, которые хотят освоить цифровые технологии, эффективно использовать цифровые инструменты в управлении и в организации образовательного процесса, повышать качество обучения с помощью современных цифровых решений', 'Руководители образовательных организаций\nОрганизуете и будете развивать цифровую образовательную среду школы на уровне всей организации.', 'Школа', 36, 'kpk', 'заочная с применением дистанционных образовательных технологий', 5400, '[{"number": 1, "title": "Роль цифровой образовательной среды в современной школе"}, {"number": 2, "title": "Цифровые компетенции педагогического работника"}, {"number": 3, "title": "Управление цифровой школой"}]', '{"knowledge": ["понятия современной цифровой образовательной среды", "направлений и инструментов цифровизации образовательного процесса и системы управления образовательной организацией", "способов интеграции цифровых технологий в сферу управления образованием"], "skills": ["применять цифровые инструменты и сервисы для создания авторских цифровых образовательных материалов", "использовать образовательные ресурсы для оценивания результатов обучающихся", "применять возможности  интеграции цифровых технологий в сферу управления образованием"], "abilities": ["организации и управления цифровой образовательной средой"]}', NULL, 1, 45);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ФОРМИРОВАНИЕ ЛИЧНОСТНЫХ И МЕТАПРЕДМЕТНЫХ РЕЗУЛЬТАТОВ У ОБУЧАЮЩИХСЯ В СООТВЕТСТВИИ С ТРЕБОВАНИЯМИ ОБНОВЛЕННОГО ФГОС НОО', 'formirovanie-lichnostnyh-i-metapredmetnyh-rezultatov-u-obuchayuschihsya-v-sootvetstvii-s-trebovaniyami-obnovlennogo-fgos', 'Курс для учителей начальных классов, которые хотят освоить современные подходы и инструменты формирования личностных и метапредметных результатов у обучающихся в соответствии с обновлённым ФГОС НОО.', 'Учитель начальных классов\nОсвоите методы формирования и развития личностных и метапредметных результатов через урочную и внеурочную деятельность.\nМетодист\nНаучитесь планировать систему формирования личностных и метапредметных результатов.', 'Школа', 24, 'kpk', 'заочная с применением дистанционных образовательных технологий', 4500, '[{"number": 1, "title": "Системно-деятельностный подход в современной школе в условиях реализации обновленного ФГОС НОО"}, {"number": 2, "title": "Формирование личностных результатов на уровне начального общего образования"}, {"number": 3, "title": "Формирование метапредметных результатов на уровне начального общего образования"}, {"number": 4, "title": "Особенности оценки достижения личностных и метапредметных результатов у обучающихся начальной школы в соответствии с требованиями ФГОС"}]', '{"knowledge": ["нормативно-правовых основ реализации обновлённого ФГОС НОО", "принципов системно-деятельностного подхода в обучении", "содержания и структуры личностных и метапредметных результатов начального общего образования"], "skills": ["организовывать образовательный процесс на основе системно-деятельностного подхода", "проектировать уроки и внеурочную деятельность с ориентацией на формирование личностных и метапредметных результатов", "подбирать педагогические технологии и приёмы для развития универсальных учебных действий"], "abilities": ["применения современных педагогических технологий для формирования личностных и метапредметных результатов", "организации образовательной среды, способствующей развитию универсальных учебных действий", "оценки и анализа личностных и метапредметных достижений обучающихся"]}', NULL, 1, 46);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('СОВРЕМЕННЫЕ ПОДХОДЫ К ОРГАНИЗАЦИИ ДЕЯТЕЛЬНОСТИ ШКОЛЬНОГО МУЗЕЯ В УСЛОВИЯХ РЕАЛИЗАЦИИ ОБНОВЛЕННЫХ ФГОС', 'sovremennye-podhody-k-organizatsii-deyatelnosti-shkolnogo-muzeya-v-usloviyah-realizatsii-obnovlennyh-fgos', 'Курс для педагогов, стремящихся организовывать работу школьного музея профессионально и с опорой на современные передовые практики.', 'Руководитель школьного музея\nОсвоите технологии интеграции музейной педагогики в образовательный процесс.\nПедагог-организатор\nНаучитесь разрабатывать проектно-исследовательские программы на базе школьного музея, способствующие развитию патриотизма и краеведческой грамотности учащихся.', 'Школа', 36, 'kpk', 'заочная с применением дистанционных образовательных технологий', 4800, '[{"number": 1, "title": "Теоретические основы к организации деятельности школьных музеев в условиях реализации обновленных ФГОС"}, {"number": 2, "title": "Нормативные и методические основы организации деятельности школьных музеев"}, {"number": 3, "title": "Экспозиционная и фондовая работа школьных музеев"}, {"number": 4, "title": "Инновации в школьном музее: от теории к практике"}, {"number": 5, "title": "Создание экспозиции СВО на базе школьного музея"}]', '{"knowledge": ["нормативно-правовой документации, регламентирующей деятельность школьных музеев", "особенностей школьного музея и его основных направлениях деятельности", "единых правил организации комплектования, учета, хранения и использования музейных предметов и коллекций"], "skills": ["организовывать деятельность школьного музея в условиях реализации обновленных ФГОС", "сочетать традиционные и инновационные форматы работы в школьном музее", "мотивировать обучающихся включаться в работу школьного музея"], "abilities": ["владения методиками организации работы школьного музея в соответствии с реализацией обновленных ФГОС"]}', NULL, 1, 47);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ИНДИВИДУАЛИЗАЦИЯ В СТРУКТУРЕ ОРГАНИЗАЦИИ ОБРАЗОВАТЕЛЬНОГО ПРОЦЕССА', 'individualizatsiya-v-strukture-organizatsii-obrazovatelnogo-protsessa', 'Курс для тех, кто желает научиться применять эффективные технологические приёмы индивидуализации обучения в условиях значимых изменений ребёнка и особенностей его развития.', 'Учитель-предметник\nНаучитесь проектировать индивидуальные образовательные маршруты для учеников с разным уровнем подготовки.\nЗаместитель руководителя (завуч), методист\nОсвоите методы организации персонализированного обучения в школе, что позволит повысить эффективность образовательного процесса.', 'Школа', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 6750, '[{"number": 1, "title": "Нормативно-правовые основы индивидуализации образования"}, {"number": 2, "title": "Основные принципы индивидуализации образовательного процесса"}, {"number": 3, "title": "Диагностика и проектирование индивидуальных траекторий"}, {"number": 4, "title": "Методики и инструменты индивидуализации"}, {"number": 5, "title": "Оценка эффективности индивидуализации образовательного процесса"}, {"number": 6, "title": "Современные практики индивидуализации образовательного процесса"}]', '{"knowledge": ["нормативно-правовых оснований индивидуализации образовательного процесса", "современных тенденций в индивидуализации образовании", "методов диагностики индивидуальных особенностей учащихся"], "skills": ["разрабатывать индивидуальные образовательные траектории с учетом возрастных и психологических особенностей учащихся", "применять цифровые платформы и образовательные методы для индивидуализации обучения", "проводить диагностику познавательных интересов, способностей и затруднений обучающихся"], "abilities": ["составления индивидуальных учебных планов и адаптации образовательных программ", "тьюторского сопровождения и мотивации учащихся"]}', NULL, 1, 48);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ПРОФИЛАКТИКА СИНДРОМА ЭМОЦИОНАЛЬНОГО ВЫГОРАНИЯ ПЕДАГОГОВ', 'profilaktika-sindroma-emotsionalnogo-vygoraniya-pedagogov', 'Курс для тех, кто хочет своевременно принимать правильные меры по предупреждению возникновения синдрома эмоционального выгорания, повысить уверенность в работе педагогов и эффективность образовательного процесса.', 'Педагог-психолог \nНаучитесь распознавать ранние признаки эмоционального выгорания и факторы риска в педагогической деятельности.\nРуководитель образовательной организации \nСформируете и внедрите систему мер по профилактике и коррекции эмоционального выгорания в педагогическом коллективе.', 'Школа, Дошкольное образование', 36, 'kpk', 'заочная с применением дистанционных образовательных технологий', 3750, '[{"number": 1, "title": "Теоретические аспекты эмоционального выгорания педагогов"}, {"number": 2, "title": "Методы и инструменты диагностики синдрома эмоционального выгорания педагогов"}, {"number": 3, "title": "Организация работы по профилактике и коррекции эмоционального выгорания педагогов"}]', '{"knowledge": ["факторов и этапов возникновения и развития синдрома эмоционального выгорания у педагогов", "современных методов и инструментов диагностики синдрома эмоционального выгорания", "способов коррекции синдрома выгорания"], "skills": ["диагностировать эмоциональное состояния работников образовательной организации", "применять методы и приемы профилактики и преодоления синдрома эмоционального выгорания", "внедрять инновационные подходы в свою профессиональную деятельность с целью повышения ее эффективности и своей личной мотивации"], "abilities": ["ладеть навыками эффективной организации образовательного процесса, позволяющими снизить риск возникновения синдрома эмоционального выгорания у педагогов"]}', NULL, 1, 49);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('СОПРОВОЖДЕНИЕ ДЕЯТЕЛЬНОСТИ ДЕТСКИХ И МОЛОДЕЖНЫХ ОБЩЕСТВЕННЫХ ОБЪЕДИНЕНИЙ В ОБРАЗОВАТЕЛЬНОЙ ОРГАНИЗАЦИИ В СООТВЕТСТВИИ С ТРЕБОВАНИЯМИ ФГОС И ФООП', 'soprovozhdenie-deyatelnosti-detskih-i-molodezhnyh-obschestvennyh-obedineniy-v-obrazovatelnoy-organizatsii-v-sootvetstvii', 'Курс для тех, кто желает выстроить работу с детскими общественными объединениями в образовательной организации и помочь обучающимся реализовать себя в социально значимых видах деятельности.', 'Педагогические работники\nСможете организовывать педагогическое сопровождение детских и молодежных общественных объединений и ученического самоуправления в образовательной организации.', 'Школа', 36, 'kpk', 'заочная с применением дистанционных образовательных технологий', 4800, '[{"number": 1, "title": "Детские и молодежные общественные объединения в воспитательном пространстве образовательной организации"}, {"number": 2, "title": "Педагогическое сопровождение ученического самоуправления в образовательной организации"}, {"number": 3, "title": "Социальное проектирование: педагогическое сопровождение социальных инициатив школьников"}]', '{"knowledge": ["современных детских общественны объединений и направлений их деятельности", "особенностей работы с объединениями «Движения первых»", "моделей ученического самоуправления в школе"], "skills": ["выстраивать работу с детскими общественными объединениями в школе", "организовывать педагогическое сопровождение ученического самоуправления", "оказывать педагогическую поддержку при разработке и реализации социальных проектов школьников"], "abilities": ["педагогического сопровождения детских и молодежных общественных объединений в образовательной организации"]}', NULL, 1, 50);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ИНТЕГРАЦИЯ ТЕХНОЛОГИЙ ВИРТУАЛЬНОЙ И ДОПОЛНЕННОЙ РЕАЛЬНОСТИ В ОБРАЗОВАТЕЛЬНЫЙ ПРОЦЕСС ШКОЛЫ', 'integratsiya-tehnologiy-virtualnoy-i-dopolnennoy-realnosti-v-obrazovatelnyy-protsess-shkoly', 'Для педагогов, которые хотят внедрять технологии виртуальной и дополненной реальности в учебный процесс, создавать интерактивные уроки и проекты, повышать вовлеченность учащихся и развивать их исследовательские и творческие навыки с помощью VR/AR.', 'Учитель, педагог дополнительного образования\nНаучитесь применять программные инструменты для работы с VR/AR и разрабатывать собственные VR/AR- проекты для интеграции их в образовательный процесс', 'Школа', 16, 'kpk', 'заочная с применением дистанционных образовательных технологий', 3450, '[{"number": 1, "title": "Теоретические основы использования технологий виртуальной и дополненной реальности в образовании"}, {"number": 2, "title": "Технология виртуальной реальности"}, {"number": 3, "title": "Технология дополненной реальности"}, {"number": 4, "title": "Методика интеграции VR и AR в образовательный процесс"}]', '{"knowledge": ["понятия технологий виртуальной и дополненной реальности и их видов", "типов оборудования для применения VR/AR-технологий", "программных инструментов для работы с VR/AR-технологиями", "способов проектирования образовательного процесса с применением VR и AR"], "skills": ["применять программные инструменты для работы с VR/AR", "разрабатывать VR/AR- проекты с помощью специальных программных сред", "проектировать образовательный процесс с применением VR/AR-технологий"], "abilities": ["организации образовательного процесса с использованием VR/AR-технологий"]}', NULL, 1, 51);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ОХРАНА И ОБЕСПЕЧЕНИЕ АНТИТЕРРОРИСТИЧЕСКОЙ ЗАЩИЩЕННОСТИ И БЕЗОПАСНОСТИ В ОО', 'ohrana-i-obespechenie-antiterroristicheskoy-zaschischennosti-i-bezopasnosti-v-oo', 'Курс для руководителей и педагогов, желающих защитить образовательную организацию от террористических угроз, научиться быстро ориентироваться в опасных ситуациях, предвидеть и предотвращать их.', 'Руководители организаций и их заместители\nРазберётесь, как внедрять, контролировать и совершенствовать комплексные меры против террористических актов.\nСпециалисты, ответственные за обеспечение антитеррористической безопасности\nУзнаете порядок подготовки и проведения обязательных профилактических мероприятий по обеспечению антитеррористической защищённости.', 'Школа', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 6225, '[{"number": 1, "title": "Нормативно-правовые акты и требования к антитеррористической безопасности в ОО"}, {"number": 2, "title": "Порядок действий сотрудников ОО при возникновении террористической угрозы"}, {"number": 3, "title": "Методики и инструменты для проведения мероприятий по профилактике возникновения террористической угрозы"}]', '{"knowledge": ["нормативно-правовых актов и требований к антитеррористической безопасности в образовательной организации", "правил поведения и действий сотрудников образовательной организации при возникновении террористической угрозы", "способов и приемов защиты от терроризма и угроз", "правил и порядка оказания первой медицинской помощи пострадавшим"], "skills": ["использовать способы защиты при опасных и потенциально-опасных ситуациях террористического характера", "проводить мероприятия по профилактике возникновения террористической угрозы в образовательной организации"], "abilities": ["выкивладеть навыками, необходимыми для безопасного поведения в чрезвычайных ситуациях, в том числе при возникновении террористической угрозы", "владеть навыками предотвращения актов терроризма", "владеть навыками, необходимыми для соблюдения мер безопасного поведения в опасных ситуациях"]}', NULL, 1, 52);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ПЕДАГОГИКА ИНКЛЮЗИВНОГО ОБРАЗОВАНИЯ В УСЛОВИЯХ РЕАЛИЗАЦИИ ФГОС НОО, ООО', 'pedagogika-inklyuzivnogo-obrazovaniya-v-usloviyah-realizatsii-fgos-noo-ooo', 'Курс для тех, кому необходимо владеть системными научными знаниями по проблемам инклюзивного образования.', 'Учителя начальных классов и учителя-предметники, у которых в классе есть дети с ОВЗ\nОрганизуете инклюзивный образовательный процесс и тьюторское сопровождение, включая взаимодействие с семьей и ПМПК образовательной организации.', 'Школа, Специальное образование', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 7200, '[{"number": 1, "title": "Основы специальной педагогики и специальной психологии"}, {"number": 2, "title": "Теоретические аспекты интегрированного и инклюзивного обучения детей с ограниченными возможностями здоровья"}, {"number": 3, "title": "Комплексное сопровождение инклюзивного образовательного процесса"}]', '{"knowledge": ["нормативной базы инклюзивного бучения детей с ОВЗ", "принципов, методов, технологий, моделей инклюзивного обучения детей с ОВЗ", "основных подходов к определению специальных образовательных потребностей детей с ОВЗ"], "skills": ["определять методы и приемы обучения различных категорий обучающихся", "производить отбор технологий обучения при реализации дифференцированного подхода", "составлять конспекты урока и адаптированную рабочую программы для классов инклюзивного обучения"], "abilities": ["владеть традиционными и инновационными технологиями обучения и воспитания детей с нарушениями развития", "владеть навыками подбора и применения средств, применяемых в обучении детей с нарушениями развития", "владеть методами анализа, оценивания и прогнозирования современных образовательных процессов"]}', NULL, 1, 53);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ИНКЛЮЗИВНОЕ ОБРАЗОВАНИЕ В УСЛОВИЯХ РЕАЛИЗАЦИИ ФГОС ДО', 'inklyuzivnoe-obrazovanie-v-usloviyah-realizatsii-fgos-do', 'Курс для тех, кто желает качественно организовать обучение детей с ОВЗ, детей-инвалидов в условиях инклюзивного образования', 'Воспитатель\nОсвойте современные методики и подходы для организации и проведения образовательной деятельности с детьми с ограниченными возможностями здоровья в условиях инклюзивного дошкольного образования.\nМетодист\nНаучитесь планировать и корректировать образовательные программы с учётом требований федеральной адаптированной образовательной программы, обеспечивая поддержку педагогов и качество инклюзивного образования.\nРуководитель\nРазвивайте навыки управления и координации инклюзивных образовательных процессов в дошкольной организации с учётом нормативно-правовых изменений и специфики работы с детьми с ОВЗ.', 'Дошкольное образование, Специальное образование', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 7275, '[{"number": 1, "title": "Специальная педагогика"}, {"number": 2, "title": "Специальная психология"}, {"number": 3, "title": "Нормативно-правовые основы функционирования дошкольных образовательных организаций, обучающих детей с ОВЗ"}, {"number": 4, "title": "Проектирование и разработка адаптированных программ для работы с детьми дошкольного возраста с различными нарушениями развития"}, {"number": 5, "title": "Современные подходы к реализации права на инклюзивное образование в условиях действия ФГОС ДО"}, {"number": 6, "title": "Дифференцированные технологии инклюзивного образования в ДОО"}, {"number": 7, "title": "Тьюторское сопровождение в инклюзивном образовательном пространстве"}]', '{"knowledge": ["нормативно-правовых и методологических изменений в сфере дошкольного образования", "нормативно-правовых оснований инклюзивного обучения и воспитания детей с ОВЗ", "сходства и различия примерной адаптированной основной образовательной программы и федеральной адаптированной образовательной программы", "содержания и особенностей ФАОП ДО, сопутствующие нормативные документы и сроки"], "skills": ["планировать свою деятельность и организовать образовательную деятельность в соответствии с ФАОП ДО", "актуализировать свою профессиональную деятельность в соответствии с изменениями законодательства Российской Федерации в области специального образования", "корректировать имеющиеся программы с учетом требований ФАОП ДО"], "abilities": ["владеть навыками проектирования организационно-содержательных моделей, форм и методов коррекционной деятельности, соответствующими условиям и возможностям слушателя"]}', NULL, 1, 54);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('СОВРЕМЕННЫЕ ЦИФРОВЫЕ ИНСТРУМЕНТЫ В ОБРАЗОВАНИИ: ОСВОЕНИЕ СЕРВИСОВ НЕЙРОСЕТЕЙ', 'sovremennye-tsifrovye-instrumenty-v-obrazovanii-osvoenie-servisov-neyrosetey', 'Курс для тех, кто хочет интегрировать нейросетевые технологии в решение педагогических задач.', 'Учитель, воспитатель\nОсвоите навыки работы с нейросетевыми инструментами: от точной формулировки запросов до создания образовательного контента в разных форматах.\nМетодист\nНаучитесь подбирать нейросетевые инструменты под образовательные задачи, формулировать точные запросы и создавать методические материалы с помощью ИИ.\nРуководитель\nОсвоите нейросетевые технологии для внедрения инноваций и стратегического развития цифрового образовательного контента в вашей организации.', 'Дошкольное образование, Школа', 36, 'kpk', 'заочная с применением дистанционных образовательных технологий', 4800, '[{"number": 1, "title": "Введение в нейросети и их применение в образовании"}, {"number": 2, "title": "Применение нейросетей в работе педагога"}, {"number": 3, "title": "Промпт-инжиниринг: продвинутые техники конструирования запросов"}, {"number": 4, "title": "Цифровые компетенции современного педагога"}]', '{"knowledge": ["принципов работы нейросетей и их роль в современном образовании, включая основные направления и возможности их применения в педагогической деятельности", "видов нейросетевых инструментов (текстовые, графические, аудио- и видеогенераторы) и их роль в оптимизации образовательного процесса"], "skills": ["выбирать и применять нейросетевые инструменты для создания образовательного контента, соответствующего образовательным задачам", "формулировать и задавать точные и эффективные запросы для взаимодействия с нейросетевыми моделями", "создавать образовательный контент (текст, изображения, аудио, видео и презентации) с использованием нейросетей"], "abilities": ["применения нейросетевых технологий в образовательном процессе"]}', NULL, 1, 55);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('МЕТОДИКА ПРЕПОДАВАНИЯ ПРЕДМЕТА "ИНОСТРАННЫЙ ЯЗЫК" В СООТВЕТСТВИИ С ОБНОВЛЕННЫМИ ФГОС  И ФОП НОО', 'metodika-prepodavaniya-predmeta-inostrannyy-yazyk-v-sootvetstvii-s-obnovlennymi-fgos-i-fop-noo', 'Курс для тех, кто хочет эффективно выстраивать обучение английскому языку в начальной школе в соответствии с обновлённым ФГОС НОО и использовать современные методики и технологии преподавания.', 'Учитель начальных классов, учитель иностранного языка\nОсвоите оммуникативные методы и цифровые инструменты преподавания, позволяющие формировать у учащихся практические языковые навыки в соответствии с требованиями ФГОС.\nМетодист, заместитель руководителя\nНаучитесь адаптировать рабочие программы под требования ФОП НОО, обеспечивая преемственность в обучении и повышая качество языковой подготовки в школе.', 'Школа', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 7200, '[{"number": 1, "title": "Требования обновленного ФГОС НОО в обучении иностранным языкам обучающихся младшей школы"}, {"number": 2, "title": "Методы и приемы формирования коммуникативных умений на уроках иностранного языка (английский) в начальной школе"}, {"number": 3, "title": "Методы и приемы формирования языковых знаний на уроках иностранного языка (английский) в начальной школе"}, {"number": 4, "title": "Современные технологии в обучении иностранным языкам обучающихся младшей школы"}]', '{"knowledge": ["содержания и особенностей обновлённых ФГОС и ФОП НОО в организации обучения иностранным языкам (английский) в начальных классах", "психолого-педагогические основ обучения младших школьников", "содержания, основных принципов и подходов к обучению иностранному языку (английский) в начальных классах"], "skills": ["подбирать образовательные подходы и инструменты, которые учитывают возрастные особенности младших школьников", "организовывать и планировать процесс обучения иностранным языкам в начальных классах в соответствии с ФГОС и ФОП НОО", "применять методы и приемы формирования коммуникативных умений для обучения иностранному языку (английский) в начальной школе"], "abilities": ["планирования и организации образовательного процесса на основе требований ФГОС и ФОП НОО", "интеграции современных образовательных технологий в учебный процесс", "адаптации учебных материалов под индивидуальные потребности учащихся"]}', NULL, 1, 56);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ОРГАНИЗАЦИОННО-ПЕДАГОГИЧЕСКОЕ СОПРОВОЖДЕНИЕ ТУРИСТСКО-КРАЕВЕДЧЕСКОЙ ДЕЯТЕЛЬНОСТИ ДЕТЕЙ В ОБРАЗОВАТЕЛЬНОЙ ОРГАНИЗАЦИИ', 'organizatsionno-pedagogicheskoe-soprovozhdenie-turistsko-kraevedcheskoy-deyatelnosti-detey-v-obrazovatelnoy-organizatsii', 'Этот курс для педагогов, которые интересуются вопросами интеграции туризма и краеведения в образовательный процесс и хотят сделать эту деятельность познавательной и полезной для детей.', 'Учитель\nОсвоите методики включения туристско-краеведческого материала в урочную и внеурочную деятельность, научитесь разрабатывать и проводить учебные и внеурочные занятия с опорой на краеведение и местные маршруты.\nКлассный руководитель\nНаучитесь использовать туристско-краеведческую деятельность как инструмент воспитания, сплочения коллектива и формирования гражданской идентичности класса.\nПедагог-организатор\nОсвоите формы и модели организации массовых туристско-краеведческих мероприятий в школе (слёты, походы, конкурсы, акции).', 'Школа, Дополнительное образование', 36, 'kpk', 'заочная с применением дистанционных образовательных технологий', 4800, '[{"number": 1, "title": "Нормативно-правовое обеспечение туристско-краеведческой деятельности"}, {"number": 2, "title": "Содержание и формы туристскокраеведческой деятельности в образовательной организации"}, {"number": 3, "title": "Актуальные практики воспитания в детско-юношеском туризме и краеведении"}, {"number": 4, "title": "Практические рекомендации по организации походов выходного дня для школьников"}]', '{"knowledge": ["нормативно-правового обеспечения организации туристско-краеведческой деятельности в образовательной организации", "особенностей детско-юношеского туризма", "особенностей организации образовательной деятельности в рамках различных форм туризма"], "skills": ["организовывать различные виды туристско-краеведческой деятельности; планировать и проводить походы выходного дня"], "abilities": ["владения актуальными практиками воспитания в детско-юношеском туризме и краеведении"]}', NULL, 1, 57);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('СОВРЕМЕННЫЕ ПОДХОДЫ К ОБРАЗОВАНИЮ ДЕТЕЙ С ОВЗ В УСЛОВИЯХ ОСНОВНОГО ОБЩЕГО ОБРАЗОВАНИЯ', 'sovremennye-podhody-k-obrazovaniyu-detey-s-ovz-v-usloviyah-osnovnogo-obschego-obrazovaniya', 'Курс для педагогов 5-9 классов, работающих с детьми с ОВЗ и желающих разобраться в их психофизических особенностях, образовательных потребностях, специфике обучения и тонкостях учебно-воспитательного процесса.', 'Учитель\nПолучите практические инструменты для работы с детьми с ОВЗ для их комфортного включения в образовательный процесс.\nПедагог-дефектолог\nУзнаете методики адаптации учебных материалов и оценивания для детей с особыми образовательными потребностями.', 'Специальное образование', 36, 'kpk', 'заочная с применением дистанционных образовательных технологий', 3750, '[{"number": 1, "title": "Психофизические особенности и образовательные потребности детей с ОВЗ различных нозологий"}, {"number": 2, "title": "Специфика обучения и воспитания детей с ОВЗ на уровне основного общего образования в условиях реализации ФГОС"}, {"number": 3, "title": "Особенности учебно-воспитательного процесса в инклюзивных классах для детей с ОВЗ"}, {"number": 4, "title": "Система комплексного сопровождения ребенка с проблемами в развитии в условиях инклюзивного обучения"}]', '{"knowledge": ["особенностей реализации ФАОП ООО для обучающихся с ОВЗ", "этапов инклюзивного урока", "психолого-педагогических и инклюзивных технологий", "специфики проектирования современного урока с учетом особых образовательных потребностей обучающихся с ОВЗ"], "skills": ["выделять индивидуальные, возрастные психологические особенности обучающихся с ОВЗ", "проектировать современный урок с учетом особых образовательных потребностей обучающихся с ОВЗ", "планировать свою деятельность и организовать образовательную деятельность в соответствии с ФАОП ООО для обучающихся с ОВЗ"], "abilities": ["применения современных подходов к образованию детей с ОВЗ в условиях основного общего образования"]}', NULL, 1, 58);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('МЕТОДИКА ПРЕПОДАВАНИЯ ПРАВИЛ ДОРОЖНОГО ДВИЖЕНИЯ В РАМКАХ УРОЧНОЙ И ВНЕУРОЧНОЙ ДЕЯТЕЛЬНОСТИ', 'metodika-prepodavaniya-pravil-dorozhnogo-dvizheniya-v-ramkah-urochnoy-i-vneurochnoy-deyatelnosti', 'Курс для тех, кто хочет выстроить эффективную систему работы по формированию основ безопасного поведения на дорогах', 'Учителям и классным руководителям\nБудете обучать правилам дорожного движения в урочной и внеурочной деятельности и формировать у детей основы безопасного поведения на улицах и дорогах.', 'Школа', 36, 'kpk', 'заочная с применением дистанционных образовательных технологий', 5250, '[{"number": 1, "title": "Методика формирования основ безопасного поведения на дорогах и улицах населенных пунктов"}, {"number": 2, "title": "Организация обучения школьников ПДД в урочной и внеурочной деятельности"}, {"number": 3, "title": "Организация работы школьного отряда «Юный инспектор дорожного движения»"}, {"number": 4, "title": "Работа с родителями обучающихся по формированию основ безопасного поведения"}]', '{"knowledge": ["системы работы по формированию основ безопасного поведения на дорогах", "системы контроля и оценивания знаний школьников по вопросам основ безопасного поведения на дорогах", "основ безопасного поведения на дорогах на занятиях предметного и межпредметного содержания"], "skills": ["организовывать работу по профилактике детского дорожно-транспортного травматизма (в условиях реализации ФГОС) в урочное и внеурочное время", "диагностировать проблемы формирования у детей основ безопасного поведения на дорогах"], "abilities": ["владеть методиками и технологиями организации просветительской и профилактической работы по вопросам безопасного поведения на дорогах"]}', NULL, 1, 59);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('СОДЕРЖАНИЕ И УСЛОВИЯ РЕАЛИЗАЦИИ ПРОГРАММЫ ВОСПИТАНИЯ В УСЛОВИЯХ РЕАЛИЗАЦИИ ФОП', 'soderzhanie-i-usloviya-realizatsii-programmy-vospitaniya-v-usloviyah-realizatsii-fop', 'Курс для тех, кто желает научиться применять современные подходы и актуальные инструменты организации воспитательной работы в школе в соответствии с новыми требованиями российского законодательства в области воспитания.', 'Учитель-предметник\nОсвоите подходы к включению целей и задач Программы воспитания в свои уроки, научитесь видеть воспитательный потенциал предметного содержания и реализовывать его в соответствии с ФОП.\nРуководитель (администрация школы: директор, зам. директора по ВР)\nСможете выстроить целостную систему воспитательной работы школы на основе Примерной рабочей программы воспитания и требований ФОП, задать целевые ориентиры и содержательные акценты для педагогического коллектива.', 'Школа', 36, 'kpk', 'заочная с применением дистанционных образовательных технологий', 4500, '[{"number": 1, "title": "Примерная рабочая программа воспитания для общеобразовательных организаций: целевые установки, новые смысловые и содержательные акценты"}, {"number": 2, "title": "Особенности планирования и организации воспитательной работы в общеобразовательной организации"}, {"number": 3, "title": "Основные направления воспитания в общеобразовательной организации"}, {"number": 4, "title": "Виды, формы и содержание воспитательной деятельности"}, {"number": 5, "title": "Анализ воспитательного процесса: принципы, направления, критерии"}]', '{"knowledge": ["Примерной программы воспитания", "законодательных нововведений в воспитательной работе", "основных направлений воспитательной работы на современном этапе", "целей и задач самоанализа воспитательной работы в школе"], "skills": ["планировать воспитательную работу в школе и в классе", "проводить профилактическую работу в школе", "проводить диагностику качества воспитательной работы в школе"], "abilities": ["владеть инструментами организации воспитательной работы в школе", "владеть навыками планирования воспитательной работы в школе и в классе"]}', NULL, 1, 60);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ДЕЯТЕЛЬНОСТЬ КЛАССНОГО РУКОВОДИТЕЛЯ ПО ПРОФИЛАКТИКЕ ЭКСТРЕМИЗМА И ТЕРРОРИЗМА СРЕДИ ШКОЛЬНИКОВ', 'deyatelnost-klassnogo-rukovoditelya-po-profilaktike-ekstremizma-i-terrorizma-sredi-shkolnikov', 'Курс для классных руководителей,которые желают узнаеть о современных проблемах, связанных с профилактикой экстремизма и терроризма, а также о методиках, которые помогут в их воспитательной работе.', 'Классный руководитель\nУзнаете признаки радикальных настроений среди подростков и методы выявления на ранних стадиях, освоите методы профилактической работы.\nСоциальный педагог\nПолучите алгоритмы взаимодействия с правоохранительными органами и родителями при возникновении потенциально опасных ситуаций, связанных с экстремистскими проявлениями.', 'Школа', 16, 'kpk', 'заочная с применением дистанционных образовательных технологий', 3450, '[{"number": 1, "title": "Теоретические и нормативные основания профилактики экстремизма и терроризма в школе"}, {"number": 2, "title": "Специфика организации и реализации воспитательных программ по профилактике экстремизма и терроризма в образовательных учреждениях"}, {"number": 3, "title": "Современные педагогические подходы и методики разработки и реализации профилактических мероприятий"}, {"number": 4, "title": "Успешные практики реализации профилактических мероприятий экстремизма и терроризма"}]', '{"knowledge": ["опасных идеологий, связанных с экстремизмом и терроризмом", "правовых и организационных основ профилактики экстремизма и терроризма среди школьников", "возрастных и психологических особенностей школьников, влияющих на их восприятие экстремизма и терроризма", "актуальных методов и форм работы с учащимися по профилактике экстремизма и терроризма"], "skills": ["разрабатывать и реализовывать программы профилактики экстремизма и терроризма среди школьников", "использовать игровые, дискуссионные, проектные методы и приёмы работы с со школьниками"], "abilities": ["владения методикой организации воспитательной работы по профилактике экстремизма и терроризма среди школьников"]}', NULL, 1, 61);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ТЬЮТОРСКОЕ СОПРОВОЖДЕНИЕ ПРОФЕССИОНАЛЬНОГО ВЫБОРА В ОСНОВНОЙ И СТАРШЕЙ ШКОЛАХ', 'tyutorskoe-soprovozhdenie-professionalnogo-vybora-v-osnovnoy-i-starshey-shkolah', 'Курс подойдет тем, кто хочет погрузиться в проектирование процесса тьюторского сопровождения профессионального выбора школьников в возрасте от 12 до 18 лет  и освоить необходимые компетенции.', 'Тьютор\nОсвоите проектирование программы тьюторского сопровождения профессионального самоопределения школьников\nУчитель-предметник\nНаучитесь встраивать элементы профессиональной навигации в содержание своего предмета, показывать связи изучаемых тем с различными профессиональными областями и возможными траекториями дальнейшего обучения.\nПедагог дополнительного образования\nОсвоите создание и реализацию программ допобразования, которые помогают подросткам примерить на себя разные профессиональные роли через проекты, мастер‑классы, конкурсы и профпробы.', 'Школа', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 11250, '[{"number": 1, "title": "Тьюторское сопровождение как механизм навигации в профессиональном самоопределение подростков"}, {"number": 2, "title": "Этапы и инструменты в работе тьютора при сопровождении в профессиональном самоопределении подростков"}, {"number": 3, "title": "Организация системы профессиональной навигации для школьников: разбор ситуационных задач"}]', '{"knowledge": ["специфики работы тьютора в вопросах профессионального самоопределения школьников", "условий для индивидуальной образовательной активности школьников в процессе становления его способностей к самоопределению, самоорганизации, осмыслению своих образовательных (жизненных) перспектив", "этапов, инструментов и технологий тьюторского сопровождения"], "skills": ["разрабатывать программу тьюторского сопровождения профессионального самоопределения обучающихся средних или старших классов школы", "составлять модель сопровождения индивидуального образовательного маршрута (ИОМ) школьников"], "abilities": ["владения технологиями тьюторского сопровождения профессионального выбора в основной и старшей школах"]}', NULL, 1, 62);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('ПРОФИЛАКТИКА СУИЦИДАЛЬНОГО ПОВЕДЕНИЯ ШКОЛЬНИКОВ', 'profilaktika-suitsidalnogo-povedeniya-shkolnikov', 'Курс для тех, кто хочет помочь детям и подросткам в кризисных состояниях и предпринять своевременные и эффективные меры предотвращения суицидальных наклонностей.', 'Педагог-психолог\nОсвоите методы раннего выявления суицидальных рисков и алгоритмы экстренного реагирования для своевременного предотвращения кризисных ситуаций.\nКлассный руководитель\nНаучитесь распознавать индикаторы суицидальных рисков в поведении учащихся и освоите техники конструктивного взаимодействия с подростками группы риска.\nСоциальный педагог\nОзнакомитесь с инструментами для организации профилактической работы с семьями учащихся, находящихся в зоне риска.', 'Школа', 36, 'kpk', 'заочная с применением дистанционных образовательных технологий', 4800, '[{"number": 1, "title": "Феноменология суицидального поведения несовершеннолетних"}, {"number": 2, "title": "Разработка программ профилактики суицидального поведения детей и подростков в образовательном пространстве школы"}]', '{"knowledge": ["психологических особенностей детей и подростков с суицидальными наклонностями", "способов выявления суицидальных настроений учащихся и методов профилактики интернет-рисков", "основных направлений, форм и технологий работы по профилактике суицида в образовательных организациях", "особенностей работы с неблагополучными семьями"], "skills": ["организовывать работу с детьми группы суицидального риска", "организовывать работу с семьей с трудными подростками", "выявлять состояния, провоцирующие риски суицидального поведения"], "abilities": ["владеть моделями психолого-педагогического сопровождения профилактики суицидального поведения обучающихся"]}', NULL, 1, 63);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('НЕЙРОТЕХНОЛОГИИ В РАБОТЕ СО ШКОЛЬНИКАМИ', 'neyrotehnologii-v-rabote-so-shkolnikami', 'Курс будет полезен педагогам начальных классов и учителям основной школы, которые хотят внедрить в свою деятельность нейроподход и освоить технологии нейрокоррекции в организации обучения и воспитания школьников.', 'Учитель начальных классов\nОсвоите нейроподход к организации уроков и внеурочной деятельности в начальной школе, подбирая задания с учётом возрастных особенностей развития мозга младших школьников.\nУчитель‑предметник (основная школа)\nНаучитесь учитывать нейрофизиологические особенности подросткового возраста при планировании уроков, чередовать виды активности так, чтобы поддерживать работоспособность и концентрацию учеников.', 'Школа', 36, 'kpk', 'заочная с применением дистанционных образовательных технологий', 4800, '[{"number": 1, "title": "Понятие о нейронауке: закономерности развития и обучения мозга"}, {"number": 2, "title": "Нейротехнологии в обучении и воспитании школьников"}, {"number": 3, "title": "Нейротехники и упражнения для развития эмоционально-волевой сферы школьников"}]', '{"knowledge": ["основных нейропсихологических проблем и способов их диагностики у обучающихся", "правил организации работы с детьми и подростками на уроке с учетом принципов нейропедагогики и нейропсихологии", "нейротехник и методик, позволяющих преодолеть трудности в обучении школьникам"], "skills": ["выявлять нейропсихологические трудности в обучении у школьников и выбирать способы нейрокоррекции; - выстраивать работу с обучающимися на уроке с учетом принципов нейронауки (нейропсихологии и нейропедагогики)", "реализовывать в работе с детьми различные нейротехники, нейроигры и упражнения с целью профилактики и коррекции проблем в обучении и воспитании"], "abilities": ["использования нейротехнологий в работе со школьниками"]}', NULL, 1, 64);
INSERT INTO courses (title, slug, description, target_audience_text, course_group, hours, program_type, learning_format, price, modules_json, outcomes_json, federal_registry_info, is_active, display_order) VALUES ('РЕАЛИЗАЦИЯ ФЕДЕРАЛЬНОЙ ОБРАЗОВАТЕЛЬНОЙ ПРОГРАММЫ ДОШКОЛЬНОГО ОБРАЗОВАНИЯ В ДОШКОЛЬНОЙ ОБРАЗОВАТЕЛЬНОЙ ОРГАНИЗАЦИИ', 'realizatsiya-federalnoy-obrazovatelnoy-programmy-doshkolnogo-obrazovaniya-v-doshkolnoy-obrazovatelnoy-organizatsii', 'Курс для воспитателей и старших воспитателей, кто желает спланировать свою деятельность и организовать образовательную деятельность ДО в соответствии с ФОП.', 'Воспитатель\nИзучите особенности обновленной федеральной образовательной программы дошкольного образования и научитесь проектировать и организовывать образовательный процесс в соответствии с ФОП ДО.\nМетодист\nОсвойте методики адаптации и внедрения ФОП ДО в дошкольной организации, а также планирование и сопровождение педагогической деятельности в новых условиях', 'Дошкольное образование', 72, 'kpk', 'заочная с применением дистанционных образовательных технологий', 7200, '[{"number": 1, "title": "Нормативно-правовые и методологические изменения в сфере дошкольного образования"}, {"number": 2, "title": "Проектирование образовательных программ с учетом ФОП"}, {"number": 3, "title": "Планирование работы педагогов в условиях ФОП"}, {"number": 4, "title": "Реализация ОП педагогами в условиях ФОП"}, {"number": 5, "title": "Планируемые результаты дошкольного образования в условиях реализации ФГОС ДО и ФОП ДО"}]', '{"knowledge": ["нормативно-правовых и методологических изменений в сфере дошкольного образования", "структуры ФОП ДО: разделы и части"], "skills": ["проектировать образовательные программы с учетом ФОП", "адаптировать программы детского сада в соответствие с ФОП ДО", "планировать свою деятельность и организовать образовательную деятельность в соответствии с ФОП"]}', NULL, 1, 65);
